    fn to_session_mode_meta_without_welcome_key() {
        let mut meta = serde_json::Map::new();
        meta.insert("unrelated".into(), serde_json::json!("value"));
        let acp_mode = acp_session_mode("kiro_default", "kiro_default", Some(meta));
        let mode = to_session_mode(&acp_mode);
        assert_eq!(mode.welcome_message(), None);
    }

    #[test]
    fn to_session_mode_non_string_welcome_is_ignored() {
        // If Kiro ever ships a non-string welcomeMessage, we drop it rather
        // than panic. A warn log is emitted (not asserted here).
        let mut meta = serde_json::Map::new();
        meta.insert("welcomeMessage".into(), serde_json::json!(42));
        let acp_mode = acp_session_mode("kiro_default", "kiro_default", Some(meta));
        let mode = to_session_mode(&acp_mode);
        assert_eq!(mode.welcome_message(), None);
    }

    #[test]
    fn to_session_mode_copies_description() {
        let mut acp_mode = acp_session_mode("chat", "chat", None);
        acp_mode.description = Some("General chat".into());
        let mode = to_session_mode(&acp_mode);
        assert_eq!(mode.description(), Some("General chat"));
    }

    #[test]
    fn to_model_info_round_trip() {
        let acp_info = acp::ModelInfo::new(
            acp::ModelId::new("claude-sonnet-4".to_string()),
            "Claude Sonnet 4",
        )
        .description(Some("Fast model".to_string()));
        let info = to_model_info(&acp_info);
        assert_eq!(info.id().as_str(), "claude-sonnet-4");
        assert_eq!(info.name(), "Claude Sonnet 4");
        assert_eq!(info.description(), Some("Fast model"));
    }

    #[test]
    fn to_model_info_no_description() {
        let acp_info = acp::ModelInfo::new(acp::ModelId::new("claude-haiku".to_string()), "Haiku");
        let info = to_model_info(&acp_info);
        assert_eq!(info.description(), None);
    }

    // --- session_created_from_response helper tests ---

    fn acp_mode_with_welcome(id: &str, name: &str, welcome: Option<&str>) -> acp::SessionMode {
        let mut m = acp::SessionMode::new(acp::SessionModeId::new(id.to_string()), name);
        if let Some(w) = welcome {
            let mut meta = serde_json::Map::new();
            meta.insert("welcomeMessage".into(), serde_json::json!(w));
            m.meta = Some(meta);
        }
        m
    }

    #[test]
    fn session_created_from_response_populates_modes_and_welcome() {
        let mode_state = acp::SessionModeState::new(
            acp::SessionModeId::new("kiro_planner".to_string()),
            vec![
                acp_mode_with_welcome("kiro_default", "kiro_default", None),
                acp_mode_with_welcome(
                    "kiro_planner",
                    "kiro_planner",
                    Some("Transform any idea..."),
                ),
            ],
        );

        let notif = session_created_from_response("s1".into(), Some(&mode_state), None);
        match notif {
            Notification::SessionCreated {
                session_id,
                current_mode,
                current_model,
                available_modes,
                available_models,
            } => {
                assert_eq!(session_id.as_str(), "s1");
                assert_eq!(
                    current_mode.as_ref().map(ModeId::as_str),
                    Some("kiro_planner")
                );
                assert_eq!(current_model, None);
                assert_eq!(available_modes.len(), 2);
                assert_eq!(
                    available_modes[1].welcome_message(),
                    Some("Transform any idea...")
                );
                assert!(available_models.is_empty());
            }
            other => panic!("expected SessionCreated, got {other:?}"),
        }
    }

    #[test]
    fn session_created_from_response_populates_models() {
        let model_state = acp::SessionModelState::new(
            acp::ModelId::new("claude-sonnet-4".to_string()),
            vec![
                acp::ModelInfo::new(acp::ModelId::new("claude-sonnet-4".to_string()), "Sonnet"),
                acp::ModelInfo::new(acp::ModelId::new("claude-haiku".to_string()), "Haiku"),
            ],
        );

        let notif = session_created_from_response("s1".into(), None, Some(&model_state));
        match notif {
            Notification::SessionCreated {
                current_model,
                available_modes,
                available_models,
                ..
            } => {
                assert_eq!(current_model.as_deref(), Some("claude-sonnet-4"));
                assert!(available_modes.is_empty());
                assert_eq!(available_models.len(), 2);
                assert_eq!(available_models[0].id().as_str(), "claude-sonnet-4");
                assert_eq!(available_models[1].name(), "Haiku");
            }
            other => panic!("expected SessionCreated, got {other:?}"),
        }
    }

    #[test]
    fn session_created_from_response_none_none_yields_empty_catalogs() {
        let notif = session_created_from_response("s1".into(), None, None);
        match notif {
            Notification::SessionCreated {
                session_id,
                current_mode,
                current_model,
                available_modes,
                available_models,
            } => {
                assert_eq!(session_id.as_str(), "s1");
                assert!(current_mode.is_none());
                assert!(current_model.is_none());
                assert!(available_modes.is_empty());
                assert!(available_models.is_empty());
            }
            other => panic!("expected SessionCreated, got {other:?}"),
        }
    }
}

//! Kiro-specific extension parsing.
//!
//! `kiro.dev/*` methods, subagent metadata, and other Kiro-only ACP
//! extensions live here. Generic ACP conversion stays in `super`.
//!
//! Note: on the wire these methods appear with a leading underscore
//! (`_kiro.dev/...`) because the public `agent-client-protocol` crate
//! auto-prefixes outbound extension method names with `_` and auto-strips
//! them inbound. The names without underscore are the canonical form.

use crate::types::*;

/// Parse a single subagent entry from a `subagent/list_update` JSON array element.
fn parse_subagent_entry(v: &serde_json::Value) -> Option<SubagentInfo> {
    let session_id = match v
        .get("sessionId")
        .and_then(|s| s.as_str())
        .filter(|s| !s.is_empty())
    {
        Some(id) => SessionId::new(id),
        None => {
            tracing::warn!("subagent entry missing or empty sessionId, skipping");
            return None;
        }
    };
    let session_name = v
        .get("sessionName")
        .and_then(|n| n.as_str())
        .filter(|s| !s.is_empty())
        .unwrap_or_else(|| {
            tracing::warn!("subagent entry missing sessionName");
            "(unknown)"
        });
    let agent_name = v
        .get("agentName")
        .and_then(|n| n.as_str())
        .filter(|s| !s.is_empty())
        .unwrap_or_else(|| {
            tracing::warn!("subagent entry missing agentName");
            "(unknown)"
        });
    let initial_query = v
        .get("initialQuery")
        .and_then(|q| q.as_str())
        .unwrap_or_default();

    let status_obj = v.get("status");
    if status_obj.is_none() {
        tracing::warn!("subagent entry missing status field, defaulting to Working");
    }
    let status_type = status_obj
        .and_then(|s| s.get("type"))
        .and_then(|t| t.as_str())
        .unwrap_or("working");
    let working_message = status_obj
        .and_then(|s| s.get("message"))
        .and_then(|m| m.as_str())
        .map(String::from);
    let status = match status_type {
        "working" => SubagentStatus::Working {
            message: working_message,
        },
        "terminated" => SubagentStatus::Terminated,
        other => {
            tracing::warn!(
                status = other,
                "unknown subagent status type, treating as Working"
            );
            SubagentStatus::Working {
                message: working_message,
            }
        }
    };

    let group = v.get("group").and_then(|g| g.as_str()).map(String::from);
    let role = v.get("role").and_then(|r| r.as_str()).map(String::from);
    let depends_on = parse_string_array(v, "dependsOn");

    Some(
        SubagentInfo::new(session_id, session_name, agent_name, initial_query, status)
            .with_group(group)
            .with_role(role)
            .with_depends_on(depends_on),
    )
}

/// Parse a single pending stage entry from a `subagent/list_update` JSON array element.
fn parse_pending_stage(v: &serde_json::Value) -> Option<PendingStage> {
    let name = match v
        .get("name")
        .and_then(|n| n.as_str())
        .filter(|s| !s.is_empty())
    {
        Some(n) => n,
        None => {
            tracing::warn!("pending stage entry missing or empty name, skipping");
            return None;
        }
    };
    let agent_name = v
        .get("agentName")
        .and_then(|n| n.as_str())
        .map(String::from);
    let group = v.get("group").and_then(|g| g.as_str()).map(String::from);
    let role = v.get("role").and_then(|r| r.as_str()).map(String::from);
    let depends_on = parse_string_array(v, "dependsOn");

    Some(PendingStage::new(name, agent_name, group, role, depends_on))
}

/// Extract a string array from a JSON value by key. Returns empty vec on missing/malformed.
fn parse_string_array(v: &serde_json::Value, key: &str) -> Vec<String> {
    v.get(key)
        .and_then(|d| d.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_str().map(String::from))
                .collect()
        })
        .unwrap_or_default()
}

pub(crate) fn to_ext_notification(
    method: &str,
    params: &serde_json::Value,
) -> crate::Result<Option<Notification>> {
    match method {
        "kiro.dev/metadata" => {
            let pct = match params
                .get("contextUsagePercentage")
                .and_then(|v| v.as_f64())
            {
                Some(v) => v,
                None => {
                    tracing::warn!(
                        "kiro.dev/metadata missing or non-numeric contextUsagePercentage"
                    );
                    0.0
                }
            };

            // Preserve zero-credit turns rather than filtering them out — a
            // turn with `meteringUsage: [{value: 0.0, ...}]` (cached
            // response, free tier, etc.) is semantically distinct from a
            // turn with the field omitted entirely. The UI layer decides
            // whether to display 0.0 or hide it.
            let metering = params
                .get("meteringUsage")
                .and_then(|m| m.as_array())
                .map(|arr| {
                    let credits: f64 = arr
                        .iter()
                        .filter_map(|u| u.get("value").and_then(|v| v.as_f64()))
                        .sum();
                    let duration_ms = params.get("turnDurationMs").and_then(|d| d.as_u64());
                    TurnMetering::new(credits, duration_ms)
                });

            let tokens = {
                let input = params.get("inputTokens").and_then(|v| v.as_u64());
                let output = params.get("outputTokens").and_then(|v| v.as_u64());
                let cached = params.get("cachedTokens").and_then(|v| v.as_u64());
                match (input, output) {
                    (Some(i), Some(o)) => Some(TokenCounts::new(i, o, cached)),
                    _ => None,
                }
            };

            Ok(Some(Notification::MetadataUpdated {
                context_usage: ContextUsage::new(pct),
                metering,
                tokens,
            }))
        }
        "kiro.dev/compaction/status" => {
            let Some(status) = params.get("status") else {
                tracing::warn!(
                    "kiro.dev/compaction/status: missing status object, dropping notification"
                );
                return Ok(None);
            };
            let status_type = status.get("type").and_then(|t| t.as_str());
            let (phase, summary) = match status_type {
                Some("started") => (CompactionPhase::Started, None),
                Some("completed") => {
                    let summary = params
                        .get("summary")
                        .and_then(|s| s.as_str())
                        .map(String::from);
                    (CompactionPhase::Completed, summary)
                }
                Some("failed") => {
                    let error = status
                        .get("error")
                        .and_then(|e| e.as_str())
                        .map(String::from);
                    (CompactionPhase::Failed { error }, None)
                }
                Some(other) => {
                    tracing::warn!(
                        status_type = other,
                        "kiro.dev/compaction/status: unknown status type, dropping"
                    );
                    return Ok(None);
                }
                None => {
                    tracing::warn!(
                        "kiro.dev/compaction/status: status object missing `type` field"
                    );
                    return Ok(None);
                }
            };
            Ok(Some(Notification::CompactionStatus { phase, summary }))
        }
        "kiro.dev/clear/status" => {
            let message = match params
                .get("message")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
            {
                Some(msg) => msg.to_string(),
                None => {
                    tracing::debug!("kiro.dev/clear/status: empty or missing message");
                    return Ok(None);
                }
            };
            Ok(Some(Notification::ClearStatus { message }))
        }
        "kiro.dev/agent/switched" => {
            let name = params
                .get("agentName")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/agent/switched: missing or empty agentName");
                    "unknown"
                })
                .to_string();
            let welcome = params
                .get("welcomeMessage")
                .and_then(|v| v.as_str())
                .map(String::from);
            let previous_agent = params
                .get("previousAgentName")
                .and_then(|v| v.as_str())
                .map(String::from);
            let model = params
                .get("model")
                .and_then(|v| v.as_str())
                .map(String::from);
            Ok(Some(Notification::AgentSwitched {
                name,
                welcome,
                previous_agent,
                model,
            }))
        }
        "kiro.dev/commands/available" => {
            // Parse the commands list from the payload.
            // Kiro sends: {"commands": [...]} or {"availableCommands": [...]} or just [...]
            let commands_value = params
                .get("commands")
                .or_else(|| params.get("availableCommands"))
                .unwrap_or(params);

            let commands = if let Some(arr) = commands_value.as_array() {
                arr.iter()
                    .filter_map(|v| {
                        let raw_name = v
                            .get("name")
                            .or_else(|| v.get("command"))
                            .and_then(|n| n.as_str())?;
                        let name = raw_name.strip_prefix('/').unwrap_or(raw_name);
                        let label = v.get("label").and_then(|l| l.as_str()).unwrap_or(name);
                        let description = v
                            .get("description")
                            .and_then(|d| d.as_str())
                            .map(String::from);

                        let meta = v.get("meta");
                        let is_selection = meta
                            .and_then(|m| m.get("inputType"))
                            .and_then(|t| t.as_str())
                            == Some("selection");
                        let is_local = meta
                            .and_then(|m| m.get("local"))
                            .and_then(|l| l.as_bool())
                            .unwrap_or(false);

                        // Backward compat: hasOptions field OR selection inputType
                        let has_options = is_selection
                            || v.get("hasOptions")
                                .and_then(|h| h.as_bool())
                                .unwrap_or(false);

                        Some(CommandInfo::new(
                            name,
                            label,
                            description,
                            has_options,
                            is_selection,
                            is_local,
                        ))
                    })
                    .collect()
            } else {
                Vec::new()
            };

            let prompts = params
                .get("prompts")
                .and_then(|p| p.as_array())
                .map(|arr| {
                    arr.iter()
                        .filter_map(|v| {
                            let name = v.get("name")?.as_str()?;
                            let description = v
                                .get("description")
                                .and_then(|d| d.as_str())
                                .map(String::from);
                            let server_name = v
                                .get("serverName")
                                .and_then(|s| s.as_str())
                                .map(String::from);
                            let arguments = v
                                .get("arguments")
                                .and_then(|a| a.as_array())
                                .map(|args| {
                                    args.iter()
                                        .filter_map(|arg| {
                                            let arg_name = arg.get("name")?.as_str()?;
                                            let required = arg
                                                .get("required")
                                                .and_then(|r| r.as_bool())
                                                .unwrap_or(false);
                                            let desc = arg
                                                .get("description")
                                                .and_then(|d| d.as_str())
                                                .map(String::from);
                                            Some(PromptArgument::new(arg_name, desc, required))
                                        })
                                        .collect()
                                })
                                .unwrap_or_default();
                            Some(PromptInfo::new(name, description, server_name, arguments))
                        })
                        .collect()
                })
                .unwrap_or_default();

            Ok(Some(Notification::CommandsUpdated { commands, prompts }))
        }
        "kiro.dev/session/update" => {
            let update = params.get("update");
            let session_update = update
                .and_then(|u| u.get("sessionUpdate"))
                .and_then(|s| s.as_str());
            match session_update {
                Some("tool_call_chunk") => {
                    let tool_call_id = match update
                        .and_then(|u| u.get("toolCallId"))
                        .and_then(|v| v.as_str())
                        .filter(|s| !s.is_empty())
                    {
                        Some(id) => id.to_string(),
                        None => {
                            tracing::warn!("tool_call_chunk missing or empty toolCallId, dropping");
                            return Ok(None);
                        }
                    };
                    let title = update
                        .and_then(|u| u.get("title"))
                        .and_then(|v| v.as_str())
                        .unwrap_or("")
                        .to_string();
                    let kind = update
                        .and_then(|u| u.get("kind"))
                        .and_then(|v| v.as_str())
                        .unwrap_or("")
                        .to_string();
                    let ext_session_id = params
                        .get("sessionId")
                        .and_then(|s| s.as_str())
                        .filter(|s| !s.is_empty())
                        .map(SessionId::new);
                    Ok(Some(Notification::ToolCallChunk {
                        tool_call_id: ToolCallId::new(tool_call_id),
                        title,
                        kind,
                        session_id: ext_session_id,
                    }))
                }
                Some(other) => {
                    tracing::debug!(variant = other, "unhandled kiro.dev/session/update variant");
                    Err(crate::Error::from_kind(crate::ErrorKind::Protocol {
                        message: format!("unhandled session/update variant: {other}"),
                    }))
                }
                None => {
                    tracing::debug!("kiro.dev/session/update missing sessionUpdate field");
                    Err(crate::Error::from_kind(crate::ErrorKind::Protocol {
                        message: "missing sessionUpdate field".into(),
                    }))
                }
            }
        }
        "kiro.dev/error/rate_limit" => {
            let message = params
                .get("message")
                .and_then(|v| v.as_str())
                .unwrap_or("Rate limit exceeded")
                .to_string();
            Ok(Some(Notification::RateLimited { message }))
        }
        "kiro.dev/mcp/server_init_failure" => {
            let server_name = params
                .get("serverName")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/mcp/server_init_failure: missing or empty serverName");
                    "unknown"
                })
                .to_string();
            let error = params
                .get("error")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .map(String::from);
            Ok(Some(Notification::McpServerInitFailure {
                server_name,
                error,
            }))
        }
        "kiro.dev/mcp/oauth_request" => {
            let server_name = params
                .get("serverName")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/mcp/oauth_request: missing or empty serverName");
                    "unknown"
                })
                .to_string();
            let url = params
                .get("oauthUrl")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or("")
                .to_string();
            if url.is_empty() {
                tracing::warn!("mcp/oauth_request missing oauthUrl");
                Ok(None)
            } else {
                Ok(Some(Notification::McpOAuthRequest { server_name, url }))
            }
        }
        "kiro.dev/mcp/server_initialized" => {
            let server_name = params
                .get("serverName")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/mcp/server_initialized: missing or empty serverName");
                    "unknown"
                })
                .to_string();
            Ok(Some(Notification::McpServerInitialized { server_name }))
        }
        "kiro.dev/agent/not_found" => {
            let requested = params
                .get("requestedAgent")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/agent/not_found: missing or empty requestedAgent");
                    "unknown"
                })
                .to_string();
            let fallback = params
                .get("fallbackAgent")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .map(String::from);
            Ok(Some(Notification::AgentNotFound {
                requested,
                fallback,
            }))
        }
        "kiro.dev/agent/config_error" => {
            let path = params
                .get("path")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/agent/config_error: missing or empty path");
                    "(unknown path)"
                })
                .to_string();
            let error = params
                .get("error")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/agent/config_error: missing or empty error");
                    "(no detail)"
                })
                .to_string();
            Ok(Some(Notification::AgentConfigError { path, error }))
        }
        "kiro.dev/model/not_found" => {
            let requested = params
                .get("requestedModel")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .unwrap_or_else(|| {
                    tracing::warn!("kiro.dev/model/not_found: missing or empty requestedModel");
                    "unknown"
                })
                .to_string();
            let fallback = params
                .get("fallbackModel")
                .and_then(|v| v.as_str())
                .filter(|s| !s.is_empty())
                .map(String::from);
            Ok(Some(Notification::ModelNotFound {
                requested,
                fallback,
            }))
        }
        "kiro.dev/subagent/list_update" => {
            let subagents_raw = params.get("subagents").and_then(|s| s.as_array());
            if subagents_raw.is_none() {
                tracing::warn!("subagent/list_update missing subagents array");
            }
            let subagents = subagents_raw
                .map(|arr| arr.iter().filter_map(parse_subagent_entry).collect())
                .unwrap_or_default();

            let pending_stages_raw = params.get("pendingStages").and_then(|s| s.as_array());
            if pending_stages_raw.is_none() && subagents_raw.is_some() {
                tracing::warn!("subagent/list_update missing pendingStages array");
            }
            let pending_stages = pending_stages_raw
                .map(|arr| arr.iter().filter_map(parse_pending_stage).collect())
                .unwrap_or_default();

            Ok(Some(Notification::SubagentListUpdated {
                subagents,
                pending_stages,
            }))
        }
        "kiro.dev/session/inbox_notification" => {
            let session_id = match params
                .get("sessionId")
                .and_then(|s| s.as_str())
                .filter(|s| !s.is_empty())
            {
                Some(id) => SessionId::new(id),
                None => {
                    tracing::warn!("inbox_notification missing or empty sessionId, dropping");
                    return Ok(None);
                }
            };
            let message_count = match params.get("messageCount").and_then(|m| m.as_u64()) {
                Some(n) => n as u32,
                None => {
                    tracing::warn!("inbox_notification missing messageCount, defaulting to 0");
                    0
                }
            };
            let escalation_count = match params.get("escalationCount").and_then(|e| e.as_u64()) {
                Some(n) => n as u32,
                None => {
                    tracing::warn!("inbox_notification missing escalationCount, defaulting to 0");
                    0
                }
            };
            let senders = params
                .get("senders")
                .and_then(|s| s.as_array())
                .map(|arr| {
                    arr.iter()
                        .filter_map(|v| v.as_str().map(String::from))
                        .collect()
                })
                .unwrap_or_default();

            Ok(Some(Notification::InboxNotification {
                session_id,
                message_count,
                escalation_count,
                senders,
            }))
        }
        "kiro.dev/session/activity" | "kiro.dev/session/list_update" => {
            tracing::debug!(
                method,
                "multi-session notification acknowledged, not forwarded"
            );
            Ok(None)
        }
        other => {
            tracing::debug!(method = other, "unknown extension notification");
            Ok(None)
        }
    }
}

use std::path::PathBuf;
use std::sync::Arc;

use tokio::sync::mpsc;

use crate::protocol::convert::session_created_from_response;
use crate::types::StopReason;
use crate::types::agent_command::AgentCommand;
use crate::types::event::{BridgeCommand, Notification, PermissionRequest, RoutedNotification};

/// Channel capacities
const COMMAND_CAPACITY: usize = 32;
const NOTIFICATION_CAPACITY: usize = 256;
const PERMISSION_CAPACITY: usize = 16;

/// Handle held by the App (Send side) to communicate with the ACP bridge.
pub struct BridgeHandle {
    command_tx: mpsc::Sender<BridgeCommand>,
    pub(crate) notification_rx: mpsc::Receiver<RoutedNotification>,
    pub(crate) permission_rx: mpsc::Receiver<PermissionRequest>,
}

impl BridgeHandle {
    /// Receive the next notification. Returns None if bridge is dead.
    pub async fn recv_notification(&mut self) -> Option<RoutedNotification> {
        self.notification_rx.recv().await
    }

    /// Receive the next permission request. Returns None if bridge is dead.
    pub async fn recv_permission(&mut self) -> Option<PermissionRequest> {
        self.permission_rx.recv().await
    }

    /// Get a cloneable sender for sending commands to the bridge.
    pub fn sender(&self) -> BridgeSender {
        BridgeSender {
            command_tx: self.command_tx.clone(),
        }
    }

    /// Split into individual receivers and a sender, for use in `tokio::select!`
    /// where borrowing `&mut self` twice is not allowed.
    pub fn split(
        self,
    ) -> (
        BridgeSender,
        mpsc::Receiver<RoutedNotification>,
        mpsc::Receiver<PermissionRequest>,
    ) {
        (
            BridgeSender {
                command_tx: self.command_tx,
            },
            self.notification_rx,
            self.permission_rx,
        )
    }
}

/// Cloneable handle for sending commands to the bridge.
/// Can be passed to spawned tasks.
#[derive(Clone)]
pub struct BridgeSender {
    command_tx: mpsc::Sender<BridgeCommand>,
}

impl BridgeSender {
    /// Create from a raw sender (used in tests and by the bridge).
    pub fn from_sender(tx: mpsc::Sender<BridgeCommand>) -> Self {
        Self { command_tx: tx }
    }

    /// Send a command to the ACP bridge. Returns Err if bridge is dead.
    pub async fn send(&self, cmd: BridgeCommand) -> crate::Result<()> {
        self.command_tx
            .send(cmd)
            .await
            .map_err(|_| crate::Error::from_kind(crate::ErrorKind::BridgeClosed))
    }
}

/// The bridge side of the channels (held by the bridge thread).
pub(crate) struct BridgeChannels {
    pub command_rx: mpsc::Receiver<BridgeCommand>,
    pub notification_tx: mpsc::Sender<RoutedNotification>,
    pub permission_tx: mpsc::Sender<PermissionRequest>,
}

/// Create a matched pair of BridgeHandle + BridgeChannels.
pub(crate) fn create_channel_pair() -> (BridgeHandle, BridgeChannels) {
    let (command_tx, command_rx) = mpsc::channel(COMMAND_CAPACITY);
    let (notification_tx, notification_rx) = mpsc::channel(NOTIFICATION_CAPACITY);
    let (permission_tx, permission_rx) = mpsc::channel(PERMISSION_CAPACITY);

    let handle = BridgeHandle {
        command_tx,
        notification_rx,
        permission_rx,
    };

    let channels = BridgeChannels {
        command_rx,
        notification_tx,
        permission_tx,
    };

    (handle, channels)
}

/// Spawn the ACP bridge on a dedicated thread.
/// Returns a BridgeHandle for the Send world to communicate through.
///
/// On any fail-stop path (runtime construction failure, `run_bridge` returning
/// `Err`), a `Notification::BridgeDisconnected` is emitted before the thread
/// exits so the App receives a structured signal instead of a silent channel
/// close.
pub fn spawn_bridge(agent_command: AgentCommand, cwd: PathBuf) -> crate::Result<BridgeHandle> {
    let (handle, channels) = create_channel_pair();
    // Cloned before `channels` is moved into the thread so that fail-stop
    // paths can still emit a final disconnect notification.
    let disconnect_tx = channels.notification_tx.clone();

    std::thread::Builder::new()
        .name("acp-bridge".into())
        .spawn(move || {
            let rt = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build();

            let exit_reason: Option<String> = match rt {
                Ok(rt) => {
                    let local = tokio::task::LocalSet::new();
                    local.block_on(&rt, async move {
                        match run_bridge(&agent_command, &cwd, channels).await {
                            Ok(()) => None,
                            Err(e) => {
                                tracing::error!(error = %e, "bridge terminated with error");
                                Some(e.to_string())
                            }
                        }
                    })
                }
                Err(e) => {
                    tracing::error!(error = %e, "failed to create bridge runtime");
                    Some(format!("failed to create bridge runtime: {e}"))
                }
            };

            if let Some(reason) = exit_reason {
                // Best-effort; the App may already have dropped its receiver.
                if let Err(send_err) = disconnect_tx.try_send(RoutedNotification {
                    session_id: None,
                    notification: Notification::BridgeDisconnected { reason },
                }) {
                    tracing::warn!(
                        error = %send_err,
                        "failed to deliver BridgeDisconnected notification on bridge exit"
                    );
                }
            }
        })
        .map_err(|e| {
            crate::Error::with_source(
                crate::ErrorKind::Transport {
                    detail: "failed to spawn bridge thread".into(),
                },
                e,
            )
        })?;

    Ok(handle)
}

/// Serialize a JSON value to an `Arc<RawValue>` for use with `ext_method`.
fn to_raw_arc(
    params: &serde_json::Value,
) -> std::result::Result<Arc<serde_json::value::RawValue>, serde_json::Error> {
    let json_str = serde_json::to_string(params)?;
    let raw = serde_json::value::RawValue::from_string(json_str)?;
    Ok(raw.into())
}

/// Parse an ACP `ExtResponse` payload into a `serde_json::Value`. Returns the
/// raw `serde_json::Error` on failure so callers can emit a `BridgeError`
/// notification distinguishing "Kiro returned malformed JSON" from "Kiro
/// returned a legitimately empty result" — the two should not collapse into
/// the same empty-picker/blank-response UI state.
fn parse_response(
    raw: &serde_json::value::RawValue,
) -> std::result::Result<serde_json::Value, serde_json::Error> {
    serde_json::from_str(raw.get())
}

/// Send a notification on the bridge channel; returns `true` if the channel
/// is closed (App died). Callers should `break` the command loop when this
/// returns true — otherwise the bridge keeps the Kiro subprocess alive after
/// the App has gone away. Use for BOTH success and error paths to keep the
/// "App disconnected" detection symmetric.
async fn notify_or_closed(
    tx: &mpsc::Sender<RoutedNotification>,
    notification: Notification,
) -> bool {
    tx.send(notification.into()).await.is_err()
}

async fn run_bridge(
    agent_command: &AgentCommand,
    cwd: &std::path::Path,
    mut channels: BridgeChannels,
) -> crate::Result<()> {
    use acp::Agent;
    use agent_client_protocol as acp;
    use tokio_util::compat::{TokioAsyncReadCompatExt, TokioAsyncWriteCompatExt};

    use crate::protocol::client::KiroClient;
    use crate::protocol::transport::AgentProcess;

    // 1. Spawn agent process
    let process = AgentProcess::spawn(agent_command, cwd).await?;

    // 2. Create KiroClient
    let client = KiroClient::new(
        channels.notification_tx.clone(),
        channels.permission_tx.clone(),
    );

    // 3. Create the ACP connection.
    //    ClientSideConnection::new returns (conn, io_task).
    //    The io_task must be spawned on the LocalSet so the RPC layer runs.
    let (conn, io_task) = acp::ClientSideConnection::new(
        client,
        process.stdin.compat_write(),
        process.stdout.compat(),
        |fut| {
            tokio::task::spawn_local(fut);
        },
    );

    // Spawn the IO pump on the local task set
    tokio::task::spawn_local(async move {
        if let Err(e) = io_task.await {
            tracing::error!(error = %e, "ACP IO task failed");
        }
    });

    // 4. ACP handshake
    let init_request = acp::InitializeRequest::new(acp::ProtocolVersion::V1)
        .client_info(acp::Implementation::new("cyril", env!("CARGO_PKG_VERSION")))
        .client_capabilities(acp::ClientCapabilities::new());

    let _init_response: acp::InitializeResponse =
        conn.initialize(init_request).await.map_err(|e| {
            crate::Error::from_kind(crate::ErrorKind::Protocol {
                message: format!("ACP initialization failed: {e}"),
            })
        })?;

    tracing::info!("ACP bridge initialized");

    // 5. Command loop
    let mut active_session_id: Option<acp::SessionId> = None;

    while let Some(cmd) = channels.command_rx.recv().await {
        match cmd {
            BridgeCommand::NewSession { cwd: session_cwd } => {
                let translated_cwd = crate::platform::path::to_agent(&session_cwd);
                match conn
                    .new_session(acp::NewSessionRequest::new(translated_cwd))
                    .await
                {
                    Ok(response) => {
                        active_session_id = Some(response.session_id.clone());
                        let notification = session_created_from_response(
                            response.session_id.to_string(),
                            response.modes.as_ref(),
                            response.models.as_ref(),
                        );
                        if notify_or_closed(&channels.notification_tx, notification).await {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(error = %e, "new_session failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeDisconnected {
                                reason: format!("Failed to create session: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SendPrompt {
                session_id,
                content_blocks,
            } => {
                let acp_session_id = acp::SessionId::new(session_id.as_str());
                let prompt: Vec<acp::ContentBlock> = content_blocks
                    .into_iter()
                    .map(acp::ContentBlock::from)
                    .collect();
                let request = acp::PromptRequest::new(acp_session_id, prompt);
                match conn.prompt(request).await {
                    Ok(response) => {
                        let stop_reason =
                            crate::protocol::convert::to_stop_reason(response.stop_reason);
                        if channels
                            .notification_tx
                            .send(Notification::TurnCompleted { stop_reason }.into())
                            .await
                            .is_err()
                        {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(error = %e, "prompt failed");
                        // Transport error — no PromptResponse available. EndTurn is a
                        // placeholder; the BridgeError notification (if sent) carries
                        // the real failure detail.
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::TurnCompleted {
                                stop_reason: StopReason::EndTurn,
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::CancelRequest => {
                if let Some(ref session_id) = active_session_id {
                    if let Err(e) = conn
                        .cancel(acp::CancelNotification::new(session_id.clone()))
                        .await
                    {
                        tracing::warn!(error = %e, "failed to send cancel notification");
                    }
                } else {
                    tracing::warn!("cancel requested but no active session");
                }
            }
            BridgeCommand::SetMode { mode_id } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(mode_id, "set_mode requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("set_mode '{mode_id}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                match conn
                    .set_session_mode(acp::SetSessionModeRequest::new(
                        session_id.clone(),
                        mode_id.clone(),
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(mode_id, "mode changed");
                    }
                    Err(e) => {
                        tracing::error!(error = %e, mode_id, "set_session_mode failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("set_mode '{mode_id}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SetModel { model_id } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(model_id, "set_model requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("set_model '{model_id}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                match conn
                    .set_session_model(acp::SetSessionModelRequest::new(
                        session_id.clone(),
                        acp::ModelId::new(model_id.clone()),
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(model_id, "model changed");
                    }
                    Err(e) => {
                        tracing::error!(error = %e, model_id, "set_session_model failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("set_model '{model_id}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::LoadSession { session_id } => {
                let acp_session_id = acp::SessionId::new(session_id.as_str());
                match conn
                    .load_session(acp::LoadSessionRequest::new(acp_session_id.clone(), cwd))
                    .await
                {
                    Ok(response) => {
                        active_session_id = Some(acp_session_id);
                        tracing::info!(session_id = session_id.as_str(), "session loaded");
                        let notification = session_created_from_response(
                            session_id.as_str().to_string(),
                            response.modes.as_ref(),
                            response.models.as_ref(),
                        );
                        if notify_or_closed(&channels.notification_tx, notification).await {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(
                            error = %e,
                            session_id = session_id.as_str(),
                            "load_session failed"
                        );
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeDisconnected {
                                reason: format!("Failed to load session: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::ExtMethod { method, params } => {
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, method, "failed to serialize ext params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("ext_method '{method}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                if let Err(e) = conn
                    .ext_method(acp::ExtRequest::new(&*method, raw_arc))
                    .await
                {
                    tracing::error!(error = %e, method, "ext_method failed");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("ext_method '{method}'"),
                            message: e.to_string(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                }
            }
            BridgeCommand::QueryCommandOptions {
                command,
                session_id,
            } => {
                let params = serde_json::json!({
                    "command": command,
                    "sessionId": session_id.as_str(),
                    // Kiro's `kiro.dev/commands/options` requires `partial:
                    // string` (docs/kiro-acp-protocol-2.0.1.md §7). We don't
                    // surface in-progress filter text to the bridge yet, so
                    // send an empty string to request the full option list.
                    "partial": "",
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, command, "failed to serialize options query");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("commands/options '{command}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/commands/options", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            let options = crate::commands::parse_options_response(&value);
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::CommandOptionsReceived { command, options },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, command, "failed to parse commands/options response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("commands/options '{command}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, command, "commands/options query failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::CommandOptionsReceived {
                                command,
                                options: vec![],
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::ExecuteCommand {
                command,
                session_id,
                args,
            } => {
                let params = serde_json::json!({
                    "sessionId": session_id.as_str(),
                    "command": {
                        "command": command,
                        "args": args,
                    }
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, command, "failed to serialize execute params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("commands/execute '{command}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/commands/execute", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::CommandExecuted {
                                    command,
                                    response: value,
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, command, "failed to parse commands/execute response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("commands/execute '{command}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, command, "commands/execute failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::CommandExecuted {
                                command,
                                response: serde_json::json!({
                                    "success": false,
                                    "error": format!("{e}"),
                                }),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SpawnSession { task, name } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(name, "spawn requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("spawn_session '{name}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                let params = serde_json::json!({
                    "sessionId": session_id.to_string(),
                    "task": task,
                    "name": name,
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize spawn params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("spawn_session '{name}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                // Wire path is the bare ACP form (`_session/spawn` on the wire,
                // sans `_kiro.dev/` prefix). Verified empirically against 2.4.1:
                // `_kiro.dev/session/spawn` returns JSON-RPC -32601 method-not-found,
                // while bare `_session/spawn` accepts the request and spawns the
                // subagent. Note this is the OPPOSITE of `session/terminate`, which
                // requires the `kiro.dev/` prefix. See `docs/cyril-acp-coverage-vs-2.4.1.md`
                // "subagent wire probe" for the captured frames.
                match conn
                    .ext_method(acp::ExtRequest::new("session/spawn", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(val) => match val.get("sessionId").and_then(|s| s.as_str()) {
                            Some(spawned_id) => {
                                tracing::info!(name, spawned_id, "spawned session");
                                if notify_or_closed(
                                    &channels.notification_tx,
                                    Notification::SubagentSpawned {
                                        session_id: crate::types::SessionId::new(spawned_id),
                                        name: name.clone(),
                                    },
                                )
                                .await
                                {
                                    break;
                                }
                            }
                            None => {
                                tracing::warn!(
                                    name,
                                    "session/spawn succeeded but response missing sessionId"
                                );
                                if notify_or_closed(
                                    &channels.notification_tx,
                                    Notification::BridgeError {
                                        operation: format!("spawn_session '{name}'"),
                                        message: "response missing sessionId".into(),
                                    },
                                )
                                .await
                                {
                                    break;
                                }
                            }
                        },
                        Err(e) => {
                            tracing::error!(error = %e, name, "failed to parse session/spawn response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("spawn_session '{name}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, name, "session/spawn failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("spawn_session '{name}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::TerminateSession { session_id: target } => {
                let params = serde_json::json!({
                    "sessionId": target.as_str(),
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize terminate params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("terminate_session '{}'", target.as_str()),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new(
                        "kiro.dev/session/terminate",
                        raw_arc,
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(session_id = target.as_str(), "terminated session");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::SubagentTerminated {
                                session_id: target.clone(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(
                            error = %e,
                            session_id = target.as_str(),
                            "session/terminate failed"
                        );
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("terminate_session '{}'", target.as_str()),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SendMessage {
                session_id: target,
                content,
            } => {
                let params = serde_json::json!({
                    "sessionId": target.as_str(),
                    "content": content,
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize message params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("send_message to '{}'", target.as_str()),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                if let Err(e) = conn
                    .ext_method(acp::ExtRequest::new("message/send", raw_arc))
                    .await
                {
                    tracing::error!(
                        error = %e,
                        session_id = target.as_str(),
                        "message/send failed"
                    );
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("send_message to '{}'", target.as_str()),
                            message: e.to_string(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                }
            }
            BridgeCommand::ListSettings => {
                // Wire request takes empty `{}` params — non-empty hangs the
                // agent (verified empirically; see coverage doc). Singleton
                // request, no sessionId.
                let raw_arc = match to_raw_arc(&serde_json::json!({})) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize settings/list params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: "settings/list".into(),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/settings/list", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::SettingsList { settings: value },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, "failed to parse settings/list response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: "settings/list".into(),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, "settings/list failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: "settings/list".into(),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::Shutdown => {
                tracing::info!("bridge shutting down");
                break;
            }
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    #![allow(clippy::unwrap_used, clippy::expect_used)]

    use super::*;

    #[tokio::test]
    async fn send_on_closed_channel_returns_error() {
        let (cmd_tx, cmd_rx) = tokio::sync::mpsc::channel(1);
        let (_, notif_rx) = tokio::sync::mpsc::channel(1);
        let (_, perm_rx) = tokio::sync::mpsc::channel(1);

        let bridge_handle = BridgeHandle {
            command_tx: cmd_tx,
            notification_rx: notif_rx,
            permission_rx: perm_rx,
        };

        let sender = bridge_handle.sender();
        // Drop the receiver for commands (simulating bridge death)
        drop(cmd_rx);
        drop(bridge_handle);

        let result = sender.send(BridgeCommand::Shutdown).await;
        assert!(result.is_err());
    }

    #[tokio::test]
    async fn recv_notification_returns_none_when_sender_dropped() {
        let (mut handle, bridge_side) = create_channel_pair();
        drop(bridge_side.notification_tx);
        let result = handle.recv_notification().await;
        assert!(result.is_none());
    }

    #[tokio::test]
    async fn recv_permission_returns_none_when_sender_dropped() {
        let (mut handle, bridge_side) = create_channel_pair();
        drop(bridge_side.permission_tx);
        let result = handle.recv_permission().await;
        assert!(result.is_none());
    }

    #[tokio::test]
    async fn notification_roundtrip() -> anyhow::Result<()> {
        let (mut handle, bridge_side) = create_channel_pair();
        let notification = Notification::TurnCompleted {
            stop_reason: StopReason::EndTurn,
        };
        bridge_side
            .notification_tx
            .send(notification.into())
            .await?;
        let received = handle.recv_notification().await.expect("notification");
        assert!(received.session_id.is_none());
        assert!(matches!(
            received.notification,
            Notification::TurnCompleted { .. }
        ));
        Ok(())
    }

    #[tokio::test]
    async fn command_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();
        sender.send(BridgeCommand::Shutdown).await?;
        let received = bridge_side.command_rx.recv().await;
        assert!(matches!(received, Some(BridgeCommand::Shutdown)));
        Ok(())
    }

    #[tokio::test]
    async fn sender_is_cloneable() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender1 = handle.sender();
        let sender2 = sender1.clone();
        sender1.send(BridgeCommand::CancelRequest).await?;
        sender2.send(BridgeCommand::Shutdown).await?;
        let r1 = bridge_side.command_rx.recv().await;
        let r2 = bridge_side.command_rx.recv().await;
        assert!(matches!(r1, Some(BridgeCommand::CancelRequest)));
        assert!(matches!(r2, Some(BridgeCommand::Shutdown)));
        Ok(())
    }

    #[tokio::test]
    async fn query_command_options_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();

        sender
            .send(BridgeCommand::QueryCommandOptions {
                command: "model".into(),
                session_id: crate::types::SessionId::new("sess_test"),
            })
            .await?;

        let cmd = bridge_side.command_rx.recv().await;
        if let Some(BridgeCommand::QueryCommandOptions {
            command,
            session_id,
        }) = cmd
        {
            assert_eq!(command, "model");
            assert_eq!(session_id.as_str(), "sess_test");
        } else {
            panic!("expected QueryCommandOptions, got {cmd:?}");
        }
        Ok(())
    }

    #[tokio::test]
    async fn execute_command_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();

        sender
            .send(BridgeCommand::ExecuteCommand {
                command: "tools".into(),
                session_id: crate::types::SessionId::new("sess_test"),
                args: serde_json::json!({}),
            })
            .await?;

        let cmd = bridge_side.command_rx.recv().await;
        if let Some(BridgeCommand::ExecuteCommand {
            command,
            session_id,
            args,
        }) = cmd
        {
            assert_eq!(command, "tools");
            assert_eq!(session_id.as_str(), "sess_test");
            assert_eq!(args, serde_json::json!({}));
        } else {
            panic!("expected ExecuteCommand, got {cmd:?}");
        }
        Ok(())
    }

    // --- parse_response ---

    // `RawValue` validates JSON at construction time in practice (Kiro's
    // `ExtResponse(Arc<RawValue>)` always holds validated bytes), so the
    // `Err` path is defensive and unreachable from legitimate inputs. Test
    // the happy path to lock the return-type contract.
    #[test]
    fn parse_response_parses_valid_json_object() {
        let raw = serde_json::value::RawValue::from_string(r#"{"ok":true}"#.into())
            .expect("build raw value");
        let value = parse_response(&raw).expect("valid JSON parses");
        assert_eq!(value["ok"], serde_json::json!(true));
    }
}

use std::cell::RefCell;
use std::collections::HashMap;

use agent_client_protocol as acp;
use async_trait::async_trait;
use tokio::sync::mpsc;

use crate::protocol::convert;
use crate::types::*;

/// The central ACP Client implementation for the bridge thread.
///
/// Lives in the `!Send` bridge thread and uses `RefCell<HashMap>` for
/// caching tool call `raw_input`. Permission requests arrive without
/// `raw_input`, so the client looks it up from this cache.
pub(crate) struct KiroClient {
    notification_tx: mpsc::Sender<RoutedNotification>,
    permission_tx: mpsc::Sender<PermissionRequest>,
    tool_call_inputs: RefCell<HashMap<String, serde_json::Value>>,
}

impl KiroClient {
    pub fn new(
        notification_tx: mpsc::Sender<RoutedNotification>,
        permission_tx: mpsc::Sender<PermissionRequest>,
    ) -> Self {
        Self {
            notification_tx,
            permission_tx,
            tool_call_inputs: RefCell::new(HashMap::new()),
        }
    }
}

#[async_trait(?Send)]
impl acp::Client for KiroClient {
    async fn request_permission(
        &self,
        args: acp::RequestPermissionRequest,
    ) -> acp::Result<acp::RequestPermissionResponse> {
        let tool_call =
            convert::to_tool_call_from_permission(&args, &self.tool_call_inputs.borrow());
        let options = convert::to_permission_options(&args);
        let message = convert::extract_permission_message(&args);

        let (responder_tx, responder_rx) = tokio::sync::oneshot::channel();

        let request = PermissionRequest {
            tool_call,
            message,
            options,
            responder: responder_tx,
        };

        self.permission_tx
            .send(request)
            .await
            .map_err(|_| acp::Error::new(-32603, "bridge closed"))?;

        let response = responder_rx
            .await
            .map_err(|_| acp::Error::new(-32603, "permission response dropped"))?;

        Ok(convert::from_permission_response(response, &args))
    }

    async fn session_notification(&self, args: acp::SessionNotification) -> acp::Result<()> {
        // Log tool call details for debugging content/locations/diff availability
        match &args.update {
            acp::SessionUpdate::ToolCall(tc) => {
                tracing::info!(
                    id = %tc.tool_call_id,
                    title = %tc.title,
                    kind = ?tc.kind,
                    status = ?tc.status,
                    content_count = tc.content.len(),
                    locations_count = tc.locations.len(),
                    has_raw_input = tc.raw_input.is_some(),
                    "ToolCall notification"
                );
            }
            acp::SessionUpdate::ToolCallUpdate(update) => {
                tracing::info!(
                    id = %update.tool_call_id,
                    title = ?update.fields.title,
                    kind = ?update.fields.kind,
                    status = ?update.fields.status,
                    has_raw_input = update.fields.raw_input.is_some(),
                    "ToolCallUpdate notification"
                );
            }
            _ => {}
        }

        convert::cache_tool_call_input(&args, &self.tool_call_inputs);

        let notification = {
            let inputs = self.tool_call_inputs.borrow();
            convert::session_update_to_notification(&args, &inputs)
        };
        if let Some(notification) = notification {
            // Every session notification carries the session_id from the
            // envelope. The App routes based on whether this matches the main
            // session or a known subagent.
            let session_id = SessionId::new(args.session_id.to_string());
            let routed = RoutedNotification::scoped(session_id, notification);
            self.notification_tx
                .send(routed)
                .await
                .map_err(|_| acp::Error::new(-32603, "bridge closed"))?;
        }

        Ok(())
    }

    async fn ext_notification(&self, args: acp::ExtNotification) -> acp::Result<()> {
        let params: serde_json::Value = match serde_json::from_str(args.params.get()) {
            Ok(v) => v,
            Err(e) => {
                tracing::error!(
                    error = %e,
                    method = %args.method,
                    "failed to parse ext_notification params"
                );
                serde_json::Value::Null
            }
        };

        match convert::kiro::to_ext_notification(args.method.as_ref(), &params) {
            Ok(Some(notification)) => {
                // ToolCallChunk carries an inline session_id from the outer
                // kiro.dev/session/update envelope. Promote it to the
                // channel-level RoutedNotification routing.
                let routed = match &notification {
                    Notification::ToolCallChunk {
                        session_id: Some(sid),
                        ..
                    } => RoutedNotification::scoped(sid.clone(), notification),
                    _ => RoutedNotification::global(notification),
                };
                self.notification_tx
                    .send(routed)
                    .await
                    .map_err(|_| acp::Error::new(-32603, "bridge closed"))?;
            }
            // Known-but-not-forwarded (multi-session), unknown, or
            // malformed-but-suppressed (e.g. oauth_request missing URL).
            // Individual handlers log warnings for the malformed cases.
            Ok(None) => {}
            Err(e) => {
                tracing::warn!(
                    error = %e,
                    method = %args.method,
                    "malformed extension notification"
                );
            }
        }
        Ok(())
    }
}

use std::path::Path;
use std::process::Stdio;
use tokio::process::{Child, ChildStdin, ChildStdout, Command};

use crate::types::AgentCommand;

pub(crate) struct AgentProcess {
    pub stdin: ChildStdin,
    pub stdout: ChildStdout,
    /// Held to keep the child process alive; dropped when the bridge shuts down.
    pub _child: Child,
}

impl AgentProcess {
    /// Spawn an ACP agent subprocess described by `cmd`.
    pub async fn spawn(cmd: &AgentCommand, cwd: &Path) -> crate::Result<Self> {
        let program = cmd.program();
        let args = cmd.args();

        let mut child = Command::new(program)
            .args(args)
            .current_dir(cwd)
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()
            .map_err(|e| {
                crate::Error::with_source(
                    crate::ErrorKind::Transport {
                        detail: format!("failed to spawn {program}"),
                    },
                    e,
                )
            })?;

        let stdin = child.stdin.take().ok_or_else(|| {
            crate::Error::from_kind(crate::ErrorKind::Transport {
                detail: "failed to capture stdin".into(),
            })
        })?;

        let stdout = child.stdout.take().ok_or_else(|| {
            crate::Error::from_kind(crate::ErrorKind::Transport {
                detail: "failed to capture stdout".into(),
            })
        })?;

        Ok(Self {
            stdin,
            stdout,
            _child: child,
        })
    }
}

use std::path::PathBuf;
use std::sync::Arc;

use tokio::sync::mpsc;

use crate::protocol::convert::session_created_from_response;
use crate::types::StopReason;
use crate::types::agent_command::AgentCommand;
use crate::types::event::{BridgeCommand, Notification, PermissionRequest, RoutedNotification};

/// Channel capacities
const COMMAND_CAPACITY: usize = 32;
const NOTIFICATION_CAPACITY: usize = 256;
const PERMISSION_CAPACITY: usize = 16;

/// Handle held by the App (Send side) to communicate with the ACP bridge.
pub struct BridgeHandle {
    command_tx: mpsc::Sender<BridgeCommand>,
    pub(crate) notification_rx: mpsc::Receiver<RoutedNotification>,
    pub(crate) permission_rx: mpsc::Receiver<PermissionRequest>,
}

impl BridgeHandle {
    /// Receive the next notification. Returns None if bridge is dead.
    pub async fn recv_notification(&mut self) -> Option<RoutedNotification> {
        self.notification_rx.recv().await
    }

    /// Receive the next permission request. Returns None if bridge is dead.
    pub async fn recv_permission(&mut self) -> Option<PermissionRequest> {
        self.permission_rx.recv().await
    }

    /// Get a cloneable sender for sending commands to the bridge.
    pub fn sender(&self) -> BridgeSender {
        BridgeSender {
            command_tx: self.command_tx.clone(),
        }
    }

    /// Split into individual receivers and a sender, for use in `tokio::select!`
    /// where borrowing `&mut self` twice is not allowed.
    pub fn split(
        self,
    ) -> (
        BridgeSender,
        mpsc::Receiver<RoutedNotification>,
        mpsc::Receiver<PermissionRequest>,
    ) {
        (
            BridgeSender {
                command_tx: self.command_tx,
            },
            self.notification_rx,
            self.permission_rx,
        )
    }
}

/// Cloneable handle for sending commands to the bridge.
/// Can be passed to spawned tasks.
#[derive(Clone)]
pub struct BridgeSender {
    command_tx: mpsc::Sender<BridgeCommand>,
}

impl BridgeSender {
    /// Create from a raw sender (used in tests and by the bridge).
    pub fn from_sender(tx: mpsc::Sender<BridgeCommand>) -> Self {
        Self { command_tx: tx }
    }

    /// Send a command to the ACP bridge. Returns Err if bridge is dead.
    pub async fn send(&self, cmd: BridgeCommand) -> crate::Result<()> {
        self.command_tx
            .send(cmd)
            .await
            .map_err(|_| crate::Error::from_kind(crate::ErrorKind::BridgeClosed))
    }
}

/// The bridge side of the channels (held by the bridge thread).
pub(crate) struct BridgeChannels {
    pub command_rx: mpsc::Receiver<BridgeCommand>,
    pub notification_tx: mpsc::Sender<RoutedNotification>,
    pub permission_tx: mpsc::Sender<PermissionRequest>,
}

/// Create a matched pair of BridgeHandle + BridgeChannels.
pub(crate) fn create_channel_pair() -> (BridgeHandle, BridgeChannels) {
    let (command_tx, command_rx) = mpsc::channel(COMMAND_CAPACITY);
    let (notification_tx, notification_rx) = mpsc::channel(NOTIFICATION_CAPACITY);
    let (permission_tx, permission_rx) = mpsc::channel(PERMISSION_CAPACITY);

    let handle = BridgeHandle {
        command_tx,
        notification_rx,
        permission_rx,
    };

    let channels = BridgeChannels {
        command_rx,
        notification_tx,
        permission_tx,
    };

    (handle, channels)
}

/// Spawn the ACP bridge on a dedicated thread.
/// Returns a BridgeHandle for the Send world to communicate through.
///
/// On any fail-stop path (runtime construction failure, `run_bridge` returning
/// `Err`), a `Notification::BridgeDisconnected` is emitted before the thread
/// exits so the App receives a structured signal instead of a silent channel
/// close.
pub fn spawn_bridge(agent_command: AgentCommand, cwd: PathBuf) -> crate::Result<BridgeHandle> {
    let (handle, channels) = create_channel_pair();
    // Cloned before `channels` is moved into the thread so that fail-stop
    // paths can still emit a final disconnect notification.
    let disconnect_tx = channels.notification_tx.clone();

    std::thread::Builder::new()
        .name("acp-bridge".into())
        .spawn(move || {
            let rt = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build();

            let exit_reason: Option<String> = match rt {
                Ok(rt) => {
                    let local = tokio::task::LocalSet::new();
                    local.block_on(&rt, async move {
                        match run_bridge(&agent_command, &cwd, channels).await {
                            Ok(()) => None,
                            Err(e) => {
                                tracing::error!(error = %e, "bridge terminated with error");
                                Some(e.to_string())
                            }
                        }
                    })
                }
                Err(e) => {
                    tracing::error!(error = %e, "failed to create bridge runtime");
                    Some(format!("failed to create bridge runtime: {e}"))
                }
            };

            if let Some(reason) = exit_reason {
                // Best-effort; the App may already have dropped its receiver.
                if let Err(send_err) = disconnect_tx.try_send(RoutedNotification {
                    session_id: None,
                    notification: Notification::BridgeDisconnected { reason },
                }) {
                    tracing::warn!(
                        error = %send_err,
                        "failed to deliver BridgeDisconnected notification on bridge exit"
                    );
                }
            }
        })
        .map_err(|e| {
            crate::Error::with_source(
                crate::ErrorKind::Transport {
                    detail: "failed to spawn bridge thread".into(),
                },
                e,
            )
        })?;

    Ok(handle)
}

/// Serialize a JSON value to an `Arc<RawValue>` for use with `ext_method`.
fn to_raw_arc(
    params: &serde_json::Value,
) -> std::result::Result<Arc<serde_json::value::RawValue>, serde_json::Error> {
    let json_str = serde_json::to_string(params)?;
    let raw = serde_json::value::RawValue::from_string(json_str)?;
    Ok(raw.into())
}

/// Parse an ACP `ExtResponse` payload into a `serde_json::Value`. Returns the
/// raw `serde_json::Error` on failure so callers can emit a `BridgeError`
/// notification distinguishing "Kiro returned malformed JSON" from "Kiro
/// returned a legitimately empty result" — the two should not collapse into
/// the same empty-picker/blank-response UI state.
fn parse_response(
    raw: &serde_json::value::RawValue,
) -> std::result::Result<serde_json::Value, serde_json::Error> {
    serde_json::from_str(raw.get())
}

/// Send a notification on the bridge channel; returns `true` if the channel
/// is closed (App died). Callers should `break` the command loop when this
/// returns true — otherwise the bridge keeps the Kiro subprocess alive after
/// the App has gone away. Use for BOTH success and error paths to keep the
/// "App disconnected" detection symmetric.
async fn notify_or_closed(
    tx: &mpsc::Sender<RoutedNotification>,
    notification: Notification,
) -> bool {
    tx.send(notification.into()).await.is_err()
}

async fn run_bridge(
    agent_command: &AgentCommand,
    cwd: &std::path::Path,
    mut channels: BridgeChannels,
) -> crate::Result<()> {
    use acp::Agent;
    use agent_client_protocol as acp;
    use tokio_util::compat::{TokioAsyncReadCompatExt, TokioAsyncWriteCompatExt};

    use crate::protocol::client::KiroClient;
    use crate::protocol::transport::AgentProcess;

    // 1. Spawn agent process
    let process = AgentProcess::spawn(agent_command, cwd).await?;

    // 2. Create KiroClient
    let client = KiroClient::new(
        channels.notification_tx.clone(),
        channels.permission_tx.clone(),
    );

    // 3. Create the ACP connection.
    //    ClientSideConnection::new returns (conn, io_task).
    //    The io_task must be spawned on the LocalSet so the RPC layer runs.
    let (conn, io_task) = acp::ClientSideConnection::new(
        client,
        process.stdin.compat_write(),
        process.stdout.compat(),
        |fut| {
            tokio::task::spawn_local(fut);
        },
    );

    // Spawn the IO pump on the local task set
    tokio::task::spawn_local(async move {
        if let Err(e) = io_task.await {
            tracing::error!(error = %e, "ACP IO task failed");
        }
    });

    // 4. ACP handshake
    let init_request = acp::InitializeRequest::new(acp::ProtocolVersion::V1)
        .client_info(acp::Implementation::new("cyril", env!("CARGO_PKG_VERSION")))
        .client_capabilities(acp::ClientCapabilities::new());

    let _init_response: acp::InitializeResponse =
        conn.initialize(init_request).await.map_err(|e| {
            crate::Error::from_kind(crate::ErrorKind::Protocol {
                message: format!("ACP initialization failed: {e}"),
            })
        })?;

    tracing::info!("ACP bridge initialized");

    // 5. Command loop
    let mut active_session_id: Option<acp::SessionId> = None;

    while let Some(cmd) = channels.command_rx.recv().await {
        match cmd {
            BridgeCommand::NewSession { cwd: session_cwd } => {
                let translated_cwd = crate::platform::path::to_agent(&session_cwd);
                match conn
                    .new_session(acp::NewSessionRequest::new(translated_cwd))
                    .await
                {
                    Ok(response) => {
                        active_session_id = Some(response.session_id.clone());
                        let notification = session_created_from_response(
                            response.session_id.to_string(),
                            response.modes.as_ref(),
                            response.models.as_ref(),
                        );
                        if notify_or_closed(&channels.notification_tx, notification).await {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(error = %e, "new_session failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeDisconnected {
                                reason: format!("Failed to create session: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SendPrompt {
                session_id,
                content_blocks,
            } => {
                let acp_session_id = acp::SessionId::new(session_id.as_str());
                let prompt: Vec<acp::ContentBlock> = content_blocks
                    .into_iter()
                    .map(acp::ContentBlock::from)
                    .collect();
                let request = acp::PromptRequest::new(acp_session_id, prompt);
                match conn.prompt(request).await {
                    Ok(response) => {
                        let stop_reason =
                            crate::protocol::convert::to_stop_reason(response.stop_reason);
                        if channels
                            .notification_tx
                            .send(Notification::TurnCompleted { stop_reason }.into())
                            .await
                            .is_err()
                        {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(error = %e, "prompt failed");
                        // Transport error — no PromptResponse available. EndTurn is a
                        // placeholder; the BridgeError notification (if sent) carries
                        // the real failure detail.
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::TurnCompleted {
                                stop_reason: StopReason::EndTurn,
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::CancelRequest => {
                if let Some(ref session_id) = active_session_id {
                    if let Err(e) = conn
                        .cancel(acp::CancelNotification::new(session_id.clone()))
                        .await
                    {
                        tracing::warn!(error = %e, "failed to send cancel notification");
                    }
                } else {
                    tracing::warn!("cancel requested but no active session");
                }
            }
            BridgeCommand::SetMode { mode_id } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(mode_id, "set_mode requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("set_mode '{mode_id}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                match conn
                    .set_session_mode(acp::SetSessionModeRequest::new(
                        session_id.clone(),
                        mode_id.clone(),
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(mode_id, "mode changed");
                    }
                    Err(e) => {
                        tracing::error!(error = %e, mode_id, "set_session_mode failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("set_mode '{mode_id}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SetModel { model_id } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(model_id, "set_model requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("set_model '{model_id}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                match conn
                    .set_session_model(acp::SetSessionModelRequest::new(
                        session_id.clone(),
                        acp::ModelId::new(model_id.clone()),
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(model_id, "model changed");
                    }
                    Err(e) => {
                        tracing::error!(error = %e, model_id, "set_session_model failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("set_model '{model_id}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::LoadSession { session_id } => {
                let acp_session_id = acp::SessionId::new(session_id.as_str());
                match conn
                    .load_session(acp::LoadSessionRequest::new(acp_session_id.clone(), cwd))
                    .await
                {
                    Ok(response) => {
                        active_session_id = Some(acp_session_id);
                        tracing::info!(session_id = session_id.as_str(), "session loaded");
                        let notification = session_created_from_response(
                            session_id.as_str().to_string(),
                            response.modes.as_ref(),
                            response.models.as_ref(),
                        );
                        if notify_or_closed(&channels.notification_tx, notification).await {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(
                            error = %e,
                            session_id = session_id.as_str(),
                            "load_session failed"
                        );
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeDisconnected {
                                reason: format!("Failed to load session: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::ExtMethod { method, params } => {
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, method, "failed to serialize ext params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("ext_method '{method}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                if let Err(e) = conn
                    .ext_method(acp::ExtRequest::new(&*method, raw_arc))
                    .await
                {
                    tracing::error!(error = %e, method, "ext_method failed");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("ext_method '{method}'"),
                            message: e.to_string(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                }
            }
            BridgeCommand::QueryCommandOptions {
                command,
                session_id,
            } => {
                let params = serde_json::json!({
                    "command": command,
                    "sessionId": session_id.as_str(),
                    // Kiro's `kiro.dev/commands/options` requires `partial:
                    // string` (docs/kiro-acp-protocol-2.0.1.md §7). We don't
                    // surface in-progress filter text to the bridge yet, so
                    // send an empty string to request the full option list.
                    "partial": "",
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, command, "failed to serialize options query");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("commands/options '{command}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/commands/options", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            let options = crate::commands::parse_options_response(&value);
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::CommandOptionsReceived { command, options },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, command, "failed to parse commands/options response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("commands/options '{command}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, command, "commands/options query failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::CommandOptionsReceived {
                                command,
                                options: vec![],
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::ExecuteCommand {
                command,
                session_id,
                args,
            } => {
                let params = serde_json::json!({
                    "sessionId": session_id.as_str(),
                    "command": {
                        "command": command,
                        "args": args,
                    }
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, command, "failed to serialize execute params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("commands/execute '{command}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/commands/execute", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::CommandExecuted {
                                    command,
                                    response: value,
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, command, "failed to parse commands/execute response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("commands/execute '{command}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, command, "commands/execute failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::CommandExecuted {
                                command,
                                response: serde_json::json!({
                                    "success": false,
                                    "error": format!("{e}"),
                                }),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SpawnSession { task, name } => {
                let Some(ref session_id) = active_session_id else {
                    tracing::warn!(name, "spawn requested but no active session");
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("spawn_session '{name}'"),
                            message: "no active session — run /new or /load first".into(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                    continue;
                };
                let params = serde_json::json!({
                    "sessionId": session_id.to_string(),
                    "task": task,
                    "name": name,
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize spawn params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("spawn_session '{name}'"),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                // Wire path is the bare ACP form (`_session/spawn` on the wire,
                // sans `_kiro.dev/` prefix). Verified empirically against 2.4.1:
                // `_kiro.dev/session/spawn` returns JSON-RPC -32601 method-not-found,
                // while bare `_session/spawn` accepts the request and spawns the
                // subagent. Note this is the OPPOSITE of `session/terminate`, which
                // requires the `kiro.dev/` prefix. See `docs/cyril-acp-coverage-vs-2.4.1.md`
                // "subagent wire probe" for the captured frames.
                match conn
                    .ext_method(acp::ExtRequest::new("session/spawn", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(val) => match val.get("sessionId").and_then(|s| s.as_str()) {
                            Some(spawned_id) => {
                                tracing::info!(name, spawned_id, "spawned session");
                                if notify_or_closed(
                                    &channels.notification_tx,
                                    Notification::SubagentSpawned {
                                        session_id: crate::types::SessionId::new(spawned_id),
                                        name: name.clone(),
                                    },
                                )
                                .await
                                {
                                    break;
                                }
                            }
                            None => {
                                tracing::warn!(
                                    name,
                                    "session/spawn succeeded but response missing sessionId"
                                );
                                if notify_or_closed(
                                    &channels.notification_tx,
                                    Notification::BridgeError {
                                        operation: format!("spawn_session '{name}'"),
                                        message: "response missing sessionId".into(),
                                    },
                                )
                                .await
                                {
                                    break;
                                }
                            }
                        },
                        Err(e) => {
                            tracing::error!(error = %e, name, "failed to parse session/spawn response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: format!("spawn_session '{name}'"),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, name, "session/spawn failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("spawn_session '{name}'"),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::TerminateSession { session_id: target } => {
                let params = serde_json::json!({
                    "sessionId": target.as_str(),
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize terminate params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("terminate_session '{}'", target.as_str()),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new(
                        "kiro.dev/session/terminate",
                        raw_arc,
                    ))
                    .await
                {
                    Ok(_) => {
                        tracing::info!(session_id = target.as_str(), "terminated session");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::SubagentTerminated {
                                session_id: target.clone(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                    Err(e) => {
                        tracing::error!(
                            error = %e,
                            session_id = target.as_str(),
                            "session/terminate failed"
                        );
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("terminate_session '{}'", target.as_str()),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::SendMessage {
                session_id: target,
                content,
            } => {
                let params = serde_json::json!({
                    "sessionId": target.as_str(),
                    "content": content,
                });
                let raw_arc = match to_raw_arc(&params) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize message params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: format!("send_message to '{}'", target.as_str()),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                if let Err(e) = conn
                    .ext_method(acp::ExtRequest::new("message/send", raw_arc))
                    .await
                {
                    tracing::error!(
                        error = %e,
                        session_id = target.as_str(),
                        "message/send failed"
                    );
                    if notify_or_closed(
                        &channels.notification_tx,
                        Notification::BridgeError {
                            operation: format!("send_message to '{}'", target.as_str()),
                            message: e.to_string(),
                        },
                    )
                    .await
                    {
                        break;
                    }
                }
            }
            BridgeCommand::ListSettings => {
                // Wire request takes empty `{}` params — non-empty hangs the
                // agent (verified empirically; see coverage doc). Singleton
                // request, no sessionId.
                let raw_arc = match to_raw_arc(&serde_json::json!({})) {
                    Ok(arc) => arc,
                    Err(e) => {
                        tracing::error!(error = %e, "failed to serialize settings/list params");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: "settings/list".into(),
                                message: format!("serialize params: {e}"),
                            },
                        )
                        .await
                        {
                            break;
                        }
                        continue;
                    }
                };
                match conn
                    .ext_method(acp::ExtRequest::new("kiro.dev/settings/list", raw_arc))
                    .await
                {
                    Ok(response) => match parse_response(&response.0) {
                        Ok(value) => {
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::SettingsList { settings: value },
                            )
                            .await
                            {
                                break;
                            }
                        }
                        Err(e) => {
                            tracing::error!(error = %e, "failed to parse settings/list response");
                            if notify_or_closed(
                                &channels.notification_tx,
                                Notification::BridgeError {
                                    operation: "settings/list".into(),
                                    message: format!("malformed JSON from kiro: {e}"),
                                },
                            )
                            .await
                            {
                                break;
                            }
                        }
                    },
                    Err(e) => {
                        tracing::error!(error = %e, "settings/list failed");
                        if notify_or_closed(
                            &channels.notification_tx,
                            Notification::BridgeError {
                                operation: "settings/list".into(),
                                message: e.to_string(),
                            },
                        )
                        .await
                        {
                            break;
                        }
                    }
                }
            }
            BridgeCommand::Shutdown => {
                tracing::info!("bridge shutting down");
                break;
            }
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    #![allow(clippy::unwrap_used, clippy::expect_used)]

    use super::*;

    #[tokio::test]
    async fn send_on_closed_channel_returns_error() {
        let (cmd_tx, cmd_rx) = tokio::sync::mpsc::channel(1);
        let (_, notif_rx) = tokio::sync::mpsc::channel(1);
        let (_, perm_rx) = tokio::sync::mpsc::channel(1);

        let bridge_handle = BridgeHandle {
            command_tx: cmd_tx,
            notification_rx: notif_rx,
            permission_rx: perm_rx,
        };

        let sender = bridge_handle.sender();
        // Drop the receiver for commands (simulating bridge death)
        drop(cmd_rx);
        drop(bridge_handle);

        let result = sender.send(BridgeCommand::Shutdown).await;
        assert!(result.is_err());
    }

    #[tokio::test]
    async fn recv_notification_returns_none_when_sender_dropped() {
        let (mut handle, bridge_side) = create_channel_pair();
        drop(bridge_side.notification_tx);
        let result = handle.recv_notification().await;
        assert!(result.is_none());
    }

    #[tokio::test]
    async fn recv_permission_returns_none_when_sender_dropped() {
        let (mut handle, bridge_side) = create_channel_pair();
        drop(bridge_side.permission_tx);
        let result = handle.recv_permission().await;
        assert!(result.is_none());
    }

    #[tokio::test]
    async fn notification_roundtrip() -> anyhow::Result<()> {
        let (mut handle, bridge_side) = create_channel_pair();
        let notification = Notification::TurnCompleted {
            stop_reason: StopReason::EndTurn,
        };
        bridge_side
            .notification_tx
            .send(notification.into())
            .await?;
        let received = handle.recv_notification().await.expect("notification");
        assert!(received.session_id.is_none());
        assert!(matches!(
            received.notification,
            Notification::TurnCompleted { .. }
        ));
        Ok(())
    }

    #[tokio::test]
    async fn command_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();
        sender.send(BridgeCommand::Shutdown).await?;
        let received = bridge_side.command_rx.recv().await;
        assert!(matches!(received, Some(BridgeCommand::Shutdown)));
        Ok(())
    }

    #[tokio::test]
    async fn sender_is_cloneable() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender1 = handle.sender();
        let sender2 = sender1.clone();
        sender1.send(BridgeCommand::CancelRequest).await?;
        sender2.send(BridgeCommand::Shutdown).await?;
        let r1 = bridge_side.command_rx.recv().await;
        let r2 = bridge_side.command_rx.recv().await;
        assert!(matches!(r1, Some(BridgeCommand::CancelRequest)));
        assert!(matches!(r2, Some(BridgeCommand::Shutdown)));
        Ok(())
    }

    #[tokio::test]
    async fn query_command_options_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();

        sender
            .send(BridgeCommand::QueryCommandOptions {
                command: "model".into(),
                session_id: crate::types::SessionId::new("sess_test"),
            })
            .await?;

        let cmd = bridge_side.command_rx.recv().await;
        if let Some(BridgeCommand::QueryCommandOptions {
            command,
            session_id,
        }) = cmd
        {
            assert_eq!(command, "model");
            assert_eq!(session_id.as_str(), "sess_test");
        } else {
            panic!("expected QueryCommandOptions, got {cmd:?}");
        }
        Ok(())
    }

    #[tokio::test]
    async fn execute_command_roundtrip() -> anyhow::Result<()> {
        let (handle, mut bridge_side) = create_channel_pair();
        let sender = handle.sender();

        sender
            .send(BridgeCommand::ExecuteCommand {
                command: "tools".into(),
                session_id: crate::types::SessionId::new("sess_test"),
                args: serde_json::json!({}),
            })
            .await?;

        let cmd = bridge_side.command_rx.recv().await;
        if let Some(BridgeCommand::ExecuteCommand {
            command,
            session_id,
            args,
        }) = cmd
        {
            assert_eq!(command, "tools");
            assert_eq!(session_id.as_str(), "sess_test");
            assert_eq!(args, serde_json::json!({}));
        } else {
            panic!("expected ExecuteCommand, got {cmd:?}");
        }
        Ok(())
    }

    // --- parse_response ---

    // `RawValue` validates JSON at construction time in practice (Kiro's
    // `ExtResponse(Arc<RawValue>)` always holds validated bytes), so the
    // `Err` path is defensive and unreachable from legitimate inputs. Test
    // the happy path to lock the return-type contract.
    #[test]
    fn parse_response_parses_valid_json_object() {
        let raw = serde_json::value::RawValue::from_string(r#"{"ok":true}"#.into())
            .expect("build raw value");
        let value = parse_response(&raw).expect("valid JSON parses");
        assert_eq!(value["ok"], serde_json::json!(true));
    }
}

use std::cell::RefCell;
use std::collections::HashMap;

use agent_client_protocol as acp;

use crate::types::*;

pub(crate) mod kiro;

pub(crate) fn to_tool_kind(kind: agent_client_protocol::ToolKind) -> ToolKind {
    match kind {
        agent_client_protocol::ToolKind::Read => ToolKind::Read,
        agent_client_protocol::ToolKind::Edit
        | agent_client_protocol::ToolKind::Delete
        | agent_client_protocol::ToolKind::Move => ToolKind::Write,
        agent_client_protocol::ToolKind::Execute => ToolKind::Execute,
        agent_client_protocol::ToolKind::Search => ToolKind::Search,
        agent_client_protocol::ToolKind::Think => ToolKind::Think,
        agent_client_protocol::ToolKind::Fetch => ToolKind::Fetch,
        agent_client_protocol::ToolKind::SwitchMode => ToolKind::SwitchMode,
        _ => ToolKind::Other,
    }
}

/// Convert an ACP `SessionMode` into cyril's domain type, lifting the
/// Kiro-specific `_meta.welcomeMessage` field out of the `_meta` bag.
pub(crate) fn to_session_mode(mode: &acp::SessionMode) -> SessionMode {
    let welcome = mode.meta.as_ref().and_then(|m| {
        m.get("welcomeMessage").and_then(|v| match v.as_str() {
            Some(s) => Some(s.to_string()),
            None => {
                tracing::warn!(
                    mode_id = %mode.id,
                    value = ?v,
                    "_meta.welcomeMessage present but not a string, ignoring"
                );
                None
            }
        })
    });
    SessionMode::new(
        ModeId::new(mode.id.to_string()),
        mode.name.clone(),
        mode.description.clone(),
    )
    .with_welcome_message(welcome)
}

/// Convert an ACP `ModelInfo` into cyril's domain type.
pub(crate) fn to_model_info(info: &acp::ModelInfo) -> ModelInfo {
    ModelInfo::new(
        ModelId::new(info.model_id.to_string()),
        info.name.clone(),
        info.description.clone(),
    )
}

/// Build a `SessionCreated` notification from the mode/model state returned
/// by `session/new` or `session/load`. Consolidates the ACP→cyril conversion
/// in one place alongside the per-item converters it calls.
pub(crate) fn session_created_from_response(
    session_id: String,
    modes: Option<&acp::SessionModeState>,
    models: Option<&acp::SessionModelState>,
) -> Notification {
    let current_mode = modes.map(|m| ModeId::new(m.current_mode_id.to_string()));
    let available_modes: Vec<SessionMode> = modes
        .map(|m| m.available_modes.iter().map(to_session_mode).collect())
        .unwrap_or_default();
    let current_model = models.map(|m| m.current_model_id.to_string());
    let available_models: Vec<ModelInfo> = models
        .map(|m| m.available_models.iter().map(to_model_info).collect())
        .unwrap_or_default();
    Notification::SessionCreated {
        session_id: SessionId::new(session_id),
        current_mode,
        current_model,
        available_modes,
        available_models,
    }
}

pub(crate) fn to_stop_reason(reason: agent_client_protocol::StopReason) -> StopReason {
    match reason {
        agent_client_protocol::StopReason::EndTurn => StopReason::EndTurn,
        agent_client_protocol::StopReason::MaxTokens => StopReason::MaxTokens,
        agent_client_protocol::StopReason::MaxTurnRequests => StopReason::MaxTurnRequests,
        agent_client_protocol::StopReason::Refusal => StopReason::Refusal,
        agent_client_protocol::StopReason::Cancelled => StopReason::Cancelled,
        _ => {
            tracing::warn!(?reason, "unknown StopReason variant, defaulting to EndTurn");
            StopReason::EndTurn
        }
    }
}

pub(crate) fn to_tool_call_status(status: agent_client_protocol::ToolCallStatus) -> ToolCallStatus {
    match status {
        agent_client_protocol::ToolCallStatus::InProgress => ToolCallStatus::InProgress,
        agent_client_protocol::ToolCallStatus::Pending => ToolCallStatus::Pending,
        agent_client_protocol::ToolCallStatus::Completed => ToolCallStatus::Completed,
        _ => ToolCallStatus::Failed,
    }
}

pub(crate) fn to_tool_call(
    acp_call: &agent_client_protocol::ToolCall,
    cached_inputs: &std::collections::HashMap<String, serde_json::Value>,
) -> ToolCall {
    let id_str = acp_call.tool_call_id.to_string();

    let content = convert_tool_call_content(&acp_call.content);
    let locations = convert_tool_call_locations(&acp_call.locations);

    ToolCall::new(
        ToolCallId::new(id_str.clone()),
        acp_call.title.clone(),
        to_tool_kind(acp_call.kind),
        to_tool_call_status(acp_call.status),
        cached_inputs
            .get(&id_str)
            .cloned()
            .or_else(|| acp_call.raw_input.clone()),
    )
    .with_content(content)
    .with_locations(locations)
    .with_raw_output(acp_call.raw_output.clone())
}

/// Convert ACP tool call content to our internal representation.
fn convert_tool_call_content(acp_content: &[acp::ToolCallContent]) -> Vec<ToolCallContent> {
    acp_content
        .iter()
        .filter_map(|c| match c {
            acp::ToolCallContent::Diff(diff) => Some(ToolCallContent::Diff {
                path: diff.path.to_string_lossy().to_string(),
                old_text: diff.old_text.clone(),
                new_text: diff.new_text.clone(),
            }),
            acp::ToolCallContent::Content(content) => {
                if let acp::ContentBlock::Text(ref text) = content.content {
                    Some(ToolCallContent::Text(text.text.clone()))
                } else {
                    None
                }
            }
            _ => None,
        })
        .collect()
}

/// Convert ACP tool call locations to our internal representation.
fn convert_tool_call_locations(acp_locations: &[acp::ToolCallLocation]) -> Vec<ToolCallLocation> {
    acp_locations
        .iter()
        .map(|loc| ToolCallLocation {
            path: loc.path.to_string_lossy().to_string(),
            line: loc.line,
        })
        .collect()
}

/// Build a `ToolCall` from the `ToolCallUpdate` inside a permission request,
/// enriching it with cached `raw_input` when the update doesn't carry one.
pub(crate) fn to_tool_call_from_permission(
    args: &acp::RequestPermissionRequest,
    cached: &HashMap<String, serde_json::Value>,
) -> ToolCall {
    let update = &args.tool_call;
    let id_str = update.tool_call_id.to_string();
    let title = update.fields.title.clone().unwrap_or_default();
    let kind = update
        .fields
        .kind
        .map(to_tool_kind)
        .unwrap_or(ToolKind::Other);
    let status = update
        .fields
        .status
        .map(to_tool_call_status)
        .unwrap_or(ToolCallStatus::Pending);
    let raw_input = cached
        .get(&id_str)
        .cloned()
        .or_else(|| update.fields.raw_input.clone());

    let content = update
        .fields
        .content
        .as_deref()
        .map(convert_tool_call_content)
        .unwrap_or_default();
    let locations = update
        .fields
        .locations
        .as_deref()
        .map(convert_tool_call_locations)
        .unwrap_or_default();

    ToolCall::new(ToolCallId::new(id_str), title, kind, status, raw_input)
        .with_content(content)
        .with_locations(locations)
        .with_raw_output(update.fields.raw_output.clone())
}

/// Convert ACP permission options to our internal representation.
pub(crate) fn to_permission_options(args: &acp::RequestPermissionRequest) -> Vec<PermissionOption> {
    args.options
        .iter()
        .map(|opt| {
            let kind = match opt.kind {
                acp::PermissionOptionKind::AllowOnce => PermissionOptionKind::AllowOnce,
                acp::PermissionOptionKind::AllowAlways => PermissionOptionKind::AllowAlways,
                acp::PermissionOptionKind::RejectOnce => PermissionOptionKind::RejectOnce,
                acp::PermissionOptionKind::RejectAlways => PermissionOptionKind::RejectAlways,
                _ => {
                    tracing::warn!(
                        ?opt.kind,
                        "unknown PermissionOptionKind variant; defaulting to RejectOnce"
                    );
                    PermissionOptionKind::RejectOnce
                }
            };
            let is_destructive = matches!(
                kind,
                PermissionOptionKind::RejectOnce | PermissionOptionKind::RejectAlways
            );
            PermissionOption {
                id: opt.option_id.to_string(),
                label: opt.name.clone(),
                kind,
                is_destructive,
            }
        })
        .collect()
}

/// Extract a human-readable message from a permission request.
/// Falls back to the tool call title if no dedicated message field exists.
pub(crate) fn extract_permission_message(args: &acp::RequestPermissionRequest) -> String {
    args.tool_call
        .fields
        .title
        .clone()
        .unwrap_or_else(|| "Permission requested".to_string())
}

/// Convert our `PermissionResponse` back into an ACP `RequestPermissionResponse`.
/// Uses the option IDs from the original request to map our response variants.
pub(crate) fn from_permission_response(
    response: PermissionResponse,
    args: &acp::RequestPermissionRequest,
) -> acp::RequestPermissionResponse {
    let outcome = match response {
        PermissionResponse::Cancel => acp::RequestPermissionOutcome::Cancelled,
        PermissionResponse::AllowOnce => {
            let option_id = find_option_id(args, acp::PermissionOptionKind::AllowOnce);
            acp::RequestPermissionOutcome::Selected(acp::SelectedPermissionOutcome::new(option_id))
        }
        PermissionResponse::AllowAlways => {
            let option_id = find_option_id(args, acp::PermissionOptionKind::AllowAlways);
            acp::RequestPermissionOutcome::Selected(acp::SelectedPermissionOutcome::new(option_id))
        }
        PermissionResponse::Reject => {
            let option_id = find_option_id(args, acp::PermissionOptionKind::RejectOnce);
            acp::RequestPermissionOutcome::Selected(acp::SelectedPermissionOutcome::new(option_id))
        }
        PermissionResponse::RejectAlways => {
            let option_id = find_option_id(args, acp::PermissionOptionKind::RejectAlways);
            acp::RequestPermissionOutcome::Selected(acp::SelectedPermissionOutcome::new(option_id))
        }
    };
    acp::RequestPermissionResponse::new(outcome)
}

/// Find the option ID for a given permission kind in the request.
/// Falls back to the first option ID if the exact kind isn't found.
fn find_option_id(
    args: &acp::RequestPermissionRequest,
    target_kind: acp::PermissionOptionKind,
) -> acp::PermissionOptionId {
    if let Some(opt) = args.options.iter().find(|o| o.kind == target_kind) {
        return opt.option_id.clone();
    }

    tracing::warn!(
        ?target_kind,
        "permission option kind not found, falling back to first available option"
    );

    args.options
        .first()
        .map(|o| o.option_id.clone())
        .unwrap_or_else(|| {
            tracing::error!("no permission options available, fabricating allow_once ID");
            acp::PermissionOptionId::new("allow_once")
        })
}

/// Cache `raw_input` from tool call and tool call update notifications,
/// keyed by tool call ID. Permission requests arrive without `raw_input`,
/// so the client looks it up from this cache.
pub(crate) fn cache_tool_call_input(
    args: &acp::SessionNotification,
    cache: &RefCell<HashMap<String, serde_json::Value>>,
) {
    match &args.update {
        acp::SessionUpdate::ToolCall(tc) => {
            if let Some(ref raw_input) = tc.raw_input {
                cache
                    .borrow_mut()
                    .insert(tc.tool_call_id.to_string(), raw_input.clone());
            }
        }
        acp::SessionUpdate::ToolCallUpdate(update) => {
            if let Some(ref raw_input) = update.fields.raw_input {
                cache
                    .borrow_mut()
                    .insert(update.tool_call_id.to_string(), raw_input.clone());
            }
        }
        _ => {}
    }
}

/// Convert an ACP `SessionNotification` to our internal `Notification`.
/// Returns `None` for update types we don't surface to the UI.
pub(crate) fn session_update_to_notification(
    args: &acp::SessionNotification,
    cached_inputs: &HashMap<String, serde_json::Value>,
) -> Option<Notification> {
    match &args.update {
        acp::SessionUpdate::UserMessageChunk(chunk) => {
            if let acp::ContentBlock::Text(ref text) = chunk.content {
                Some(Notification::UserMessage(UserMessage {
                    text: text.text.clone(),
                    is_streaming: true,
                }))
            } else {
                None
            }
        }
        acp::SessionUpdate::AgentMessageChunk(chunk) => {
            if let acp::ContentBlock::Text(ref text) = chunk.content {
                Some(Notification::AgentMessage(AgentMessage {
                    text: text.text.clone(),
                    is_streaming: true,
                }))
            } else {
                None
            }
        }
        acp::SessionUpdate::AgentThoughtChunk(chunk) => {
            if let acp::ContentBlock::Text(ref text) = chunk.content {
                Some(Notification::AgentThought(AgentThought {
                    text: text.text.clone(),
                }))
            } else {
                None
            }
        }
        acp::SessionUpdate::ToolCall(tc) => Some(Notification::ToolCallStarted(to_tool_call(
            tc,
            cached_inputs,
        ))),
        acp::SessionUpdate::ToolCallUpdate(update) => {
            let id_str = update.tool_call_id.to_string();
            let title = update.fields.title.clone().unwrap_or_default();
            let kind = update
                .fields
                .kind
                .map(to_tool_kind)
                .unwrap_or(ToolKind::Other);
            let status = update
                .fields
                .status
                .map(to_tool_call_status)
                .unwrap_or(ToolCallStatus::Pending);
            let raw_input = cached_inputs
                .get(&id_str)
                .cloned()
                .or_else(|| update.fields.raw_input.clone());

            let content = update
                .fields
                .content
                .as_deref()
                .map(convert_tool_call_content)
                .unwrap_or_default();
            let locations = update
                .fields
                .locations
                .as_deref()
                .map(convert_tool_call_locations)
                .unwrap_or_default();

            Some(Notification::ToolCallUpdated(
                ToolCall::new(ToolCallId::new(id_str), title, kind, status, raw_input)
                    .with_content(content)
                    .with_locations(locations)
                    .with_raw_output(update.fields.raw_output.clone()),
            ))
        }
        acp::SessionUpdate::Plan(plan) => {
            let entries = plan
                .entries
                .iter()
                .map(|e| {
                    let status = match e.status {
                        acp::PlanEntryStatus::Pending => PlanEntryStatus::Pending,
                        acp::PlanEntryStatus::InProgress => PlanEntryStatus::InProgress,
                        acp::PlanEntryStatus::Completed => PlanEntryStatus::Completed,
                        _ => PlanEntryStatus::Failed,
                    };
                    let priority = match e.priority {
                        acp::PlanEntryPriority::High => PlanEntryPriority::High,
                        acp::PlanEntryPriority::Medium => PlanEntryPriority::Medium,
                        acp::PlanEntryPriority::Low => PlanEntryPriority::Low,
                        _ => PlanEntryPriority::Medium,
                    };
                    PlanEntry::new(e.content.clone(), status, priority)
                })
                .collect();
            Some(Notification::PlanUpdated(Plan::new(entries)))
        }
        acp::SessionUpdate::CurrentModeUpdate(mode) => Some(Notification::ModeChanged {
            mode_id: ModeId::new(mode.current_mode_id.to_string()),
        }),
        acp::SessionUpdate::ConfigOptionUpdate(update) => {
            let options = update
                .config_options
                .iter()
                .filter_map(|opt| match &opt.kind {
                    acp::SessionConfigKind::Select(select) => {
                        let values = match &select.options {
                            acp::SessionConfigSelectOptions::Ungrouped(flat) => {
                                flat.iter().map(|v| v.value.to_string()).collect()
                            }
                            acp::SessionConfigSelectOptions::Grouped(groups) => groups
                                .iter()
                                .flat_map(|g| g.options.iter().map(|v| v.value.to_string()))
                                .collect(),
                            _ => Vec::new(),
                        };
                        Some(ConfigOption {
                            key: opt.id.to_string(),
                            label: opt.name.clone(),
                            value: Some(select.current_value.to_string()),
                            options: values,
                        })
                    }
                    _ => None,
                })
                .collect();
            Some(Notification::ConfigOptionsUpdated(options))
        }
        acp::SessionUpdate::AvailableCommandsUpdate(update) => {
            let commands = update
                .available_commands
                .iter()
                .map(|cmd| {
                    CommandInfo::new(
                        cmd.name.clone(),
                        cmd.description.clone(),
                        None::<String>,
                        cmd.input.is_some(),
                        false,
                        false,
                    )
                })
                .collect();
            Some(Notification::CommandsUpdated {
                commands,
                prompts: Vec::new(),
            })
        }
        acp::SessionUpdate::UsageUpdate(usage) => {
            tracing::info!(
                used = usage.used,
                size = usage.size,
                has_cost = usage.cost.is_some(),
                "received ACP UsageUpdate (unstable_session_usage)"
            );
            Some(Notification::UsageUpdated {
                used: usage.used,
                size: usage.size,
            })
        }
        _ => {
            tracing::debug!("unhandled session update variant");
            None
        }
    }
}

