}

/// Reason the agent stopped processing a prompt turn.
///
/// We define our own enum rather than reusing `acp::StopReason` so that
/// `cyril-ui` (which must not import ACP types) can read it through the
/// `TuiState` trait.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum StopReason {
    #[default]
    EndTurn,
    MaxTokens,
    MaxTurnRequests,
    Refusal,
    Cancelled,
}

/// Atomic summary of a completed turn.
///
/// Assembled by `SessionController` when `TurnCompleted` arrives: the
/// `stop_reason` comes from the `session/prompt` response; `token_counts`
/// and `metering` were buffered from the preceding `MetadataUpdated`
/// notification. Grouping them prevents the renderer from ever seeing
/// token counts from turn N paired with a stop reason from turn N-1.
///
/// NOTE: `stop_reason` is not yet extracted from the `session/prompt` response.
/// The bridge currently hardcodes `StopReason::EndTurn` for all outcomes.
/// Task #2 in the protocol parity backlog will wire the real value.
#[derive(Debug, Clone)]
pub struct TurnSummary {
    stop_reason: StopReason,
    token_counts: Option<TokenCounts>,
    metering: Option<TurnMetering>,
}

impl TurnSummary {
    pub fn new(
        stop_reason: StopReason,
        token_counts: Option<TokenCounts>,
        metering: Option<TurnMetering>,
    ) -> Self {
        Self {
            stop_reason,
            token_counts,
            metering,
        }
    }

    pub fn stop_reason(&self) -> StopReason {
        self.stop_reason
    }

    pub fn token_counts(&self) -> Option<&TokenCounts> {
        self.token_counts.as_ref()
    }

    pub fn metering(&self) -> Option<&TurnMetering> {
        self.metering.as_ref()
    }
}

#[cfg(test)]
mod tests {
    #![allow(clippy::unwrap_used, clippy::expect_used)]

    use super::*;
    use std::collections::HashMap;

    #[test]
    fn session_id_roundtrip() {
        let id = SessionId::new("sess_123");
        assert_eq!(id.as_str(), "sess_123");
    }

    #[test]
    fn session_id_display() {
        let id = SessionId::new("sess_123");
        assert_eq!(format!("{id}"), "sess_123");
    }

    #[test]
    fn session_id_usable_as_hashmap_key() {
        let mut map = HashMap::new();
        let id = SessionId::new("sess_1");
        map.insert(id.clone(), 42);
        assert_eq!(map.get(&SessionId::new("sess_1")), Some(&42));
    }

    #[test]
    fn session_status_default_is_disconnected() {
        let status = SessionStatus::default();
        assert_eq!(status, SessionStatus::Disconnected);
    }

    #[test]
    fn session_status_error_carries_message() {
        let status = SessionStatus::Error {
            message: "oops".into(),
        };
        assert!(matches!(status, SessionStatus::Error { message } if message == "oops"));
    }

    #[test]
    fn context_usage_stores_value() {
        let usage = ContextUsage::new(50.0);
        assert!((usage.percentage() - 50.0).abs() < f64::EPSILON);
    }

    #[test]
    fn context_usage_clamps_high() {
        let usage = ContextUsage::new(150.0);
        assert!((usage.percentage() - 100.0).abs() < f64::EPSILON);
    }

    #[test]
    fn context_usage_clamps_low() {
        let usage = ContextUsage::new(-10.0);
        assert!((usage.percentage() - 0.0).abs() < f64::EPSILON);
    }

    #[test]
    fn session_mode_accessors() {
        let mode = SessionMode::new(
            ModeId::new("code"),
            "Code Mode",
            Some("Write and edit code"),
        );
        assert_eq!(mode.id().as_str(), "code");
        assert_eq!(mode.label(), "Code Mode");
        assert_eq!(mode.description(), Some("Write and edit code"));
    }

    #[test]
    fn session_mode_no_description() {
        let mode = SessionMode::new(ModeId::new("chat"), "Chat", None::<&str>);
        assert_eq!(mode.description(), None);
    }

    #[test]
    fn credit_usage_accessors() {
        let credits = CreditUsage::new(5.25, 10.0);
        assert!((credits.used() - 5.25).abs() < f64::EPSILON);
        assert!((credits.limit() - 10.0).abs() < f64::EPSILON);
    }

    #[test]
    fn session_cost_accumulates() {
        let mut cost = SessionCost::new();
        cost.record_turn(&TurnMetering::new(0.018, Some(1948)));
        cost.record_turn(&TurnMetering::new(0.042, Some(5200)));
        assert_eq!(cost.turn_count(), 2);
        assert!((cost.total_credits() - 0.060).abs() < 0.001);
        assert!((cost.last_turn_credits().unwrap() - 0.042).abs() < 0.001);
        assert_eq!(cost.last_turn_duration_ms(), Some(5200));
    }

    #[test]
    fn duration_display_formatting() {
        assert_eq!(
            TurnMetering::new(0.01, Some(500)).duration_display(),
            Some("500ms".into())
        );
        assert_eq!(
            TurnMetering::new(0.01, Some(1948)).duration_display(),
            Some("1.9s".into())
        );
        assert_eq!(
            TurnMetering::new(0.01, Some(135000)).duration_display(),
            Some("2m 15s".into())
        );
        assert!(TurnMetering::new(0.01, None).duration_display().is_none());
    }

    #[test]
    fn session_cost_default() {
        let cost = SessionCost::new();
        assert_eq!(cost.total_credits(), 0.0);
        assert_eq!(cost.turn_count(), 0);
        assert!(cost.last_turn_credits().is_none());
    }

    fn assert_send<T: Send>() {}
    fn assert_sync<T: Sync>() {}

    #[test]
    fn session_types_are_send_sync() {
        assert_send::<SessionId>();
        assert_sync::<SessionId>();
        assert_send::<SessionStatus>();
        assert_sync::<SessionStatus>();
        assert_send::<SessionMode>();
        assert_sync::<SessionMode>();
        assert_send::<ContextUsage>();
        assert_sync::<ContextUsage>();
        assert_send::<CreditUsage>();
        assert_sync::<CreditUsage>();
        assert_send::<TurnMetering>();
        assert_sync::<TurnMetering>();
        assert_send::<SessionCost>();
        assert_sync::<SessionCost>();
        assert_send::<TokenCounts>();
        assert_sync::<TokenCounts>();
    }

    #[test]
    fn stop_reason_default_is_end_turn() {
        assert_eq!(StopReason::default(), StopReason::EndTurn);
    }

    #[test]
    fn turn_summary_accessors() {
        let summary = TurnSummary::new(
            StopReason::MaxTokens,
            Some(TokenCounts::new(1000, 500, Some(200))),
            Some(TurnMetering::new(0.05, Some(3000))),
        );
        assert_eq!(summary.stop_reason(), StopReason::MaxTokens);
        assert!(summary.token_counts().is_some());
        assert!(summary.metering().is_some());
    }

    #[test]
    fn turn_summary_minimal() {
        let summary = TurnSummary::new(StopReason::Cancelled, None, None);
        assert_eq!(summary.stop_reason(), StopReason::Cancelled);
        assert!(summary.token_counts().is_none());
        assert!(summary.metering().is_none());
    }

    #[test]
    fn stop_reason_is_send_sync() {
        assert_send::<StopReason>();
        assert_sync::<StopReason>();
    }

    #[test]
    fn turn_summary_is_send_sync() {
        assert_send::<TurnSummary>();
        assert_sync::<TurnSummary>();
    }
}

pub mod bridge;
pub(crate) mod client;
pub(crate) mod convert;
pub(crate) mod transport;

            }

            // Priority 2: Notifications from bridge
            Some(notification) = self.notification_rx.recv() => {
                for deferred in self.handle_notification(notification) {
                    // SendPrompt triggers a real turn → mark session Busy.
                    // Session-management commands (LoadSession,
                    // TerminateSession) don't start a turn so leave status
                    // alone. See `/code` (busy) vs `/rewind` (not busy).
                    let starts_turn = matches!(deferred, BridgeCommand::SendPrompt { .. });
                    match self.bridge_sender.send(deferred).await {
                        Ok(()) => {
                            if starts_turn {
                                self.session.set_status(SessionStatus::Busy);
                            }
                        }
                        Err(e) => {
                            tracing::warn!(error = %e, "failed to send deferred bridge command");
                            self.ui_state.set_activity(Activity::Idle);
                            self.ui_state.add_system_message(
                                "Failed to dispatch follow-up command to agent.".into(),
                            );
                        }
                    }
                }
            }

            // Priority 3: Permission requests from bridge
            Some(request) = self.permission_rx.recv() => {
                self.ui_state.show_approval(request);
                self.redraw_needed = true;
            }

            // Priority 4: Redraw tick
            _ = redraw_interval.tick() => {
                // Flush stream buffer on tick
                if self.ui_state.flush_stream_buffer() {
                    self.redraw_needed = true;
                }

                // During busy states, redraw every tick so the activity
                // spinner animates and the elapsed timer increments.
                if !matches!(
                    self.ui_state.activity(),
                    Activity::Idle | Activity::Ready
                ) {
                    self.redraw_needed = true;
                }

                // Deep idle detection
                if self.last_activity.elapsed() > Duration::from_secs(30) {
                    self.ui_state.set_deep_idle(true);
                }
            }
        }

        // Adaptive frame rate — account for subagent activity as well as main session.
        let effective_activity = if self.ui_state.any_subagent_active() {
            Activity::Streaming
        } else {
            self.ui_state.activity()
        };
        let new_duration = Self::redraw_duration(effective_activity);
        redraw_interval = tokio::time::interval(new_duration);
        redraw_interval.set_missed_tick_behavior(tokio::time::MissedTickBehavior::Skip);

        // Conditional redraw
        if self.redraw_needed {
            terminal
                .draw(|frame| cyril_ui::render::draw(frame, &self.ui_state))
                .map_err(|e| {
                    cyril_core::Error::with_source(
                        cyril_core::ErrorKind::Transport {
                            detail: "draw failed".into(),
                        },
                        e,
                    )
                })?;
            self.redraw_needed = false;
        }

        if self.ui_state.should_quit() {
            if let Err(e) = self.bridge_sender.send(BridgeCommand::Shutdown).await {
                tracing::warn!(error = %e, "failed to send shutdown to bridge");
            }
            break;
        }
    }

    Ok(())
}

fn redraw_duration(activity: Activity) -> Duration {
    match activity {
        Activity::Streaming | Activity::ToolRunning => Duration::from_millis(50),
        Activity::Waiting | Activity::Sending => Duration::from_millis(100),
        Activity::Ready => Duration::from_millis(250),
        Activity::Idle => Duration::from_secs(1),
    }
}

fn handle_notification(&mut self, routed: RoutedNotification) -> Vec<BridgeCommand> {
    let RoutedNotification {
        session_id,
        notification,
    } = routed;

    // Tracker-level notifications (list_update, inbox) are global:
    // apply them regardless of session_id. Returns false for unrelated variants.
    let tracker_changed = self
        .ui_state
        .apply_subagent_tracker_notification(&notification);

    // SubagentListUpdated also informs SubagentUiState so it can mark terminated streams.
    if let Notification::SubagentListUpdated { ref subagents, .. } = notification {
        self.ui_state.apply_subagent_list_update(subagents);
        self.redraw_needed = true;
    }

    // Route session-scoped notifications: if the source session_id is
    // a known subagent, route to SubagentUiState and return early.
    // If session_id is None or matches the main session, fall through.
    if let Some(ref sid) = session_id {
        let is_main = self.session.id().map(|m| m == sid).unwrap_or(false);
        if !is_main && self.ui_state.subagent_tracker().is_subagent(sid) {
            self.ui_state
                .apply_subagent_notification(sid, &notification);
            self.redraw_needed = true;
            return Vec::new();
        }
        if !is_main && self.session.id().is_some() {
            // Session ID doesn't match main and isn't a known subagent.
            // This can happen if a subagent notification arrives before
            // the corresponding SubagentListUpdated. Route it optimistically —
            // the stream will be created on first contact.
            tracing::debug!(
                session_id = sid.as_str(),
                "notification for unknown session, routing to subagent stream"
            );
            self.ui_state
                .apply_subagent_notification(sid, &notification);
            self.redraw_needed = true;
            return Vec::new();
        }
    }

    let session_changed = self.session.apply_notification(&notification);
    let ui_changed = self.ui_state.apply_notification(&notification);

