    tracing_subscriber::fmt()
        .with_max_level(tracing::Level::INFO)
        .with_writer(std::io::stderr)
        .with_ansi(true)
        .init();

    let cli = Cli::parse();
    let cwd = std::env::current_dir()?;

    println!("=== Cyril v2 Bridge Test Harness ===\n");
