    println!("[OK] Done\n");

    Ok(())
}

/// Drain all notifications for `duration`, printing each one.
/// Returns the session ID if a SessionCreated notification was received.
async fn drain_notifications(
    notification_rx: &mut tokio::sync::mpsc::Receiver<RoutedNotification>,
    permission_rx: &mut tokio::sync::mpsc::Receiver<PermissionRequest>,
    duration: Duration,
) -> Option<SessionId> {
    let deadline = tokio::time::Instant::now() + duration;
    let mut session_id = None;

    loop {
        tokio::select! {
            biased;

            Some(routed) = notification_rx.recv() => {
                if let Some(ref sid) = routed.session_id {
                    println!("  [session={}]", sid.as_str());
                }
                print_notification(&routed.notification);
                if let Notification::SessionCreated { session_id: ref id, .. } = routed.notification {
                    session_id = Some(id.clone());
                }
            }

            Some(permission) = permission_rx.recv() => {
                println!("  [PERMISSION] {}", permission.message);
                for opt in &permission.options {
                    println!("    - {} (id={}, destructive={})", opt.label, opt.id, opt.is_destructive);
                }
                // Auto-approve with first non-destructive option
                let response = if permission.options.iter().any(|o| !o.is_destructive) {
                    PermissionResponse::AllowOnce
                } else {
                    PermissionResponse::Cancel
                };
                if permission.responder.send(response).is_err() {
                    eprintln!("  [WARN] permission response dropped (receiver closed)");
                }
            }

            _ = tokio::time::sleep_until(deadline) => {
                break;
            }
        }
    }

    session_id
}

fn print_notification(n: &Notification) {
    match n {
        Notification::SessionCreated {
            session_id,
            current_mode,
            current_model,
            available_modes,
            available_models,
        } => {
            println!("  [SessionCreated]");
            println!("    session_id: {}", session_id.as_str());
            println!(
                "    current_mode: {}",
                current_mode
                    .as_ref()
                    .map(|m| m.as_str())
                    .unwrap_or("(none)")
            );
            println!("    available_modes: {}", available_modes.len());
            println!("    available_models: {}", available_models.len());
            println!(
                "    current_model: {}",
                current_model.as_deref().unwrap_or("(none)")
            );
        }
        Notification::TurnCompleted { .. } => {
            println!("  [TurnCompleted]");
        }
        Notification::BridgeDisconnected { reason } => {
            println!("  [BridgeDisconnected] {reason}");
        }
        Notification::AgentMessage(msg) => {
            let preview: String = msg.text.chars().take(80).collect();
            println!(
                "  [AgentMessage] streaming={} text={preview}...",
                msg.is_streaming
            );
        }
        Notification::UserMessage(msg) => {
            let preview: String = msg.text.chars().take(80).collect();
            println!(
                "  [UserMessage] streaming={} text={preview}...",
                msg.is_streaming
            );
        }
        Notification::AgentThought(thought) => {
            let preview: String = thought.text.chars().take(80).collect();
            println!("  [AgentThought] {preview}...");
        }
        Notification::ToolCallStarted(tc) => {
            println!(
                "  [ToolCallStarted] id={} title={:?} kind={:?}",
                tc.id().as_str(),
                tc.title(),
                tc.kind()
            );
        }
        Notification::ToolCallUpdated(tc) => {
            println!(
                "  [ToolCallUpdated] id={} title={:?} status={:?}",
                tc.id().as_str(),
                tc.title(),
                tc.status()
            );
        }
        Notification::PlanUpdated(plan) => {
            println!("  [PlanUpdated] {} entries", plan.entries().len());
        }
        Notification::ModeChanged { mode_id } => {
            println!("  [ModeChanged] {mode_id}");
        }
        Notification::ConfigOptionsUpdated(options) => {
            println!("  [ConfigOptionsUpdated] {} options", options.len());
            for opt in options {
                println!(
                    "    key={} value={:?} choices={}",
                    opt.key,
                    opt.value,
                    opt.options.len()
                );
            }
        }
        Notification::CommandsUpdated {
            commands: cmds,
            prompts,
        } => {
            println!(
                "  [CommandsUpdated] {} commands, {} prompts",
                cmds.len(),
                prompts.len()
            );
            for cmd in cmds {
                println!(
                    "    {:<20} sel={:<5} local={:<5} {}",
                    cmd.name(),
                    cmd.is_selection(),
                    cmd.is_local(),
                    cmd.description().unwrap_or("")
                );
            }
        }
        Notification::MetadataUpdated {
            context_usage,
            metering,
            tokens,
        } => {
            println!(
                "  [MetadataUpdated] ctx={:.1}% metering={:?} tokens={:?}",
                context_usage.percentage(),
                metering.as_ref().map(|m| m.credits()),
                tokens.as_ref().map(|t| (t.input(), t.output(), t.cached()))
            );
        }
        Notification::AgentSwitched { name, welcome, .. } => {
            println!("  [AgentSwitched] name={name} welcome={:?}", welcome);
        }
        Notification::CompactionStatus { phase, summary } => {
            println!("  [CompactionStatus] phase={phase:?} summary={summary:?}");
        }
        Notification::ClearStatus { message } => {
            println!("  [ClearStatus] {message}");
        }
        Notification::RateLimited { message } => {
            println!("  [RateLimited] {message}");
        }
        Notification::ToolCallChunk {
            tool_call_id,
            title,
            kind,
            session_id,
        } => {
            let sid = session_id.as_ref().map_or("main", |s| s.as_str());
            println!("  [ToolCallChunk] id={tool_call_id} title={title} kind={kind} session={sid}");
        }
        Notification::CommandOptionsReceived { command, options } => {
            println!(
                "  [CommandOptionsReceived] command={command} options={}",
                options.len()
            );
            for opt in options {
                println!(
                    "    {:<30} value={:<25} current={} desc={:?} group={:?}",
                    opt.label,
                    opt.value,
                    opt.is_current,
                    opt.description.as_deref().unwrap_or(""),
                    opt.group.as_deref().unwrap_or("")
                );
            }
        }
        Notification::SettingsList { settings } => {
            let pretty = serde_json::to_string_pretty(settings)
                .unwrap_or_else(|_| settings.to_string());
            println!("  [SettingsList]");
            println!("    {}", pretty.replace('\n', "\n    "));
        }
        Notification::CommandExecuted { command, response } => {
            let success = response
                .get("success")
                .and_then(|s| s.as_bool())
                .unwrap_or(false);
            let message = response
                .get("message")
                .and_then(|m| m.as_str())
                .unwrap_or("");
            let has_data = response.get("data").is_some();
            println!("  [CommandExecuted] command={command} success={success} has_data={has_data}");
            println!("    message: {message}");
            if has_data {
                let data = response.get("data").unwrap();
                let pretty =
                    serde_json::to_string_pretty(data).unwrap_or_else(|_| data.to_string());
                // Print first 500 chars of data
                let preview: String = pretty.chars().take(500).collect();
                println!("    data: {preview}");
                if pretty.len() > 500 {
                    println!("    ... ({} more chars)", pretty.len() - 500);
                }
            }
        }
        Notification::McpServerInitFailure { server_name, error } => {
            println!(
                "  [McpInitFail] {server_name}: {}",
                error.as_deref().unwrap_or("(no detail)")
            );
        }
        Notification::McpOAuthRequest { server_name, url } => {
            println!("  [McpOAuth] {server_name}: {url}");
        }
        Notification::McpServerInitialized { server_name } => {
            println!("  [McpReady] {server_name}");
        }
        Notification::AgentNotFound {
            requested,
            fallback,
        } => {
            println!(
                "  [AgentNotFound] {requested} -> {}",
                fallback.as_deref().unwrap_or("(none)")
            );
        }
        Notification::AgentConfigError { path, error } => {
            println!("  [AgentConfigError] {path}: {error}");
        }
        Notification::ModelNotFound {
            requested,
            fallback,
        } => {
            println!(
                "  [ModelNotFound] {requested} -> {}",
                fallback.as_deref().unwrap_or("(none)")
            );
        }
        Notification::SubagentListUpdated {
            subagents,
            pending_stages,
        } => {
            println!(
                "  [SubagentList] {} active, {} pending",
                subagents.len(),
                pending_stages.len()
            );
            for s in subagents {
                let status = if s.is_working() {
                    "working"
                } else {
                    "terminated"
                };
                println!("    {} ({}) — {status}", s.session_name(), s.agent_name());
            }
            for p in pending_stages {
                println!("    {} (pending, depends: {:?})", p.name(), p.depends_on());
            }
        }
        Notification::InboxNotification {
            session_id,
            message_count,
            escalation_count,
            senders,
        } => {
            println!(
                "  [Inbox] session={} msgs={message_count} escalations={escalation_count} from={senders:?}",
                session_id.as_str()
            );
        }
        Notification::SubagentSpawned { session_id, name } => {
            println!("  [SubagentSpawned] {name} ({})", session_id.as_str());
        }
        Notification::SubagentTerminated { session_id } => {
            println!("  [SubagentTerminated] ({})", session_id.as_str());
        }
        Notification::BridgeError { operation, message } => {
            println!("  [BridgeError] {operation}: {message}");
        }
        Notification::UsageUpdated { used, size } => {
            let pct = *used as f64 / (*size).max(1) as f64 * 100.0;
            println!("  [UsageUpdated] {used}/{size} tokens ({pct:.1}%)");
        }
    }
}

